 *      divisor = (n + 0x3FFFFFFF) / n;
 *      g_a5_4902 = (g_a5_4902 * 0x6d25) + 1;  // 32-bit wrap
 *      masked   = g_a5_4902 & 0x3FFFFFFF;     // 30-bit
 *      return (short)(masked / divisor);
