	state    = (unsigned long)g_a5_4902;
	state    = state * 0x6d25UL + 1UL;
	g_a5_4902 = (long)state;
	divisor  = ((unsigned long)0x3FFFFFFFUL + (unsigned long)n)
	           / (unsigned long)n;
	if (divisor == 0)
		return 0;
	return (short)((state & 0x3FFFFFFFUL) / divisor);
