	/* deep flag = wilderness arg set AND (cell flag rec[5] or jt273) */
	deep = ((unsigned char)a_wild != 0
	        && (rec[5] != 0 || jt273() != 0)) ? 1 : 0;

	*(unsigned char **)ctx = rec;           /* ctx[0..3] = rec ptr */
