	unsigned char  buf2[398];

	PROBE("jt573");
	g_a5_word(-7002) = rec[189];
	rec[189] = 8;
	g_a5_ptr(-6996) = buf1;
	jt406(buf1, rec, 398);                  /* SWAPPED: copy(rec -> buf1) */
	g_a5_ptr(-6992) = buf2;
	jt406(buf2, rec, 398);                  /* SWAPPED: copy(rec -> buf2) */
	g_a5_byte(-7038) = 0;
	g_a5_byte(-7004) = 1;

