static void l19b2(unsigned char *a, unsigned char *b,
                  unsigned char *c, unsigned char *d) __attribute__((unused));
static void l19b2(unsigned char *a, unsigned char *b, unsigned char *c, unsigned char *d)
{
	PROBE("L19b2");
	if (*d > *c || (*d == 18 && *b > *a)) {
		*c = *d;
		*a = *b;
	}
}

/* L19f8 (CODE 18 + 0x19f8) — accumulate a per-class HP/effect bonus into *acc,
 * scaled by caster `level` (clamped to the g_a5_23007 cap for `kind`, +1 for
 * kinds 1/4). For caster kinds 1-4 the multiplier is set by the effect id
 * (*val): 15-19 -> (id-14), 20 -> 5, 21-23 -> 6, 24-25 -> 7; for other kinds,
 * id>15 -> 2 and id==15 -> 1. */
static void l19f8(short kind, short level, unsigned char *acc,
                  const unsigned char *val) __attribute__((unused));
static void l19f8(short kind, short level, unsigned char *acc, const unsigned char *val)
{
	unsigned char cap = g_a5_buf(-23007)[kind];
	short v = *val;

	PROBE("L19f8");
	if ((unsigned char)level >= cap)
		level = (short)(cap - 1);
	if (kind == 4 || kind == 1)
		level++;

	if (kind == 1 || kind == 2 || kind == 3 || kind == 4) {
		if (v >= 15 && v <= 19)       *acc = (unsigned char)(*acc + (v - 14) * level);
		else if (v == 20)             *acc = (unsigned char)(*acc + level * 5);
		else if (v >= 21 && v <= 23)  *acc = (unsigned char)(*acc + level * 6);
		else if (v >= 24 && v <= 25)  *acc = (unsigned char)(*acc + level * 7);
	} else {
		if (v > 15)        *acc = (unsigned char)(*acc + level * 2);
		else if (v == 15)  *acc = (unsigned char)(*acc + level);
	}
}

/* JT[875] (CODE 18 + 0x1b14, 18 sites) — recompute one of a character's
 * ability/derived fields (`idx`) from its base plus every relevant magic-item
 * effect, via L18fa (decode) / L19b2 (keep-best) / L19f8 (level-scaled HP).
 *   idx 0   -> Strength: scan worn effect items (item[56] bit7), then fold in
 *              jt41 effects 38/113/12, with exceptional-strength (18/xx) math;
 *              writes mp[113]/mp[124].
 *   idx 1,2 -> other ability via effect 68 -> mp[113+idx*2].
 *   idx 4   -> hit points: reset to base mp[184], sum each class's level-scaled
 *              bonus (L19f8) into mp[129], track current-HP mp[395] by the
 *              delta, then grant/remove the low-HP effect 62 (jt876/jt878).
 *   idx 5   -> effect 14 bonus -> mp[123].
 * Args are the member pointer and the field index (low byte of the word). */
static void jt875(long member, short idx) __attribute__((unused));
static void jt875(long member, short idx)
{
	unsigned char *m = (unsigned char *)(uintptr_t)member;
	unsigned char *item;
	void          *eff = 0;
	unsigned char  val, base, ev = 0, eb = 0;
	short          i = (short)(signed char)(idx & 0xff);

	PROBE("jt875");
	val  = m[112 + i * 2];
	base = m[125];

	if (i == 0) {                           /* worn effect-item scan (STR) */
		for (item = *(unsigned char **)(m + 8); item != NULL;
		     item = *(unsigned char **)item) {
			unsigned char e56;
			if (item[56] <= 128 || item[50] == 0)
				continue;
			e56 = (unsigned char)(item[56] & 0x7f);
			switch (e56) {          /* JT[3] @ 0x1b94 (min 3, max 5) */
			case 3:
				ev = 3; eb = 100;
				break;
			case 5:
				ev = (unsigned char)(item[55] + 18);
				if (ev == 18) eb = 100;
				break;
			default:                /* case 4 / out of range: no-op */
				break;
			}
			l19b2(&base, &eb, &val, &ev);
		}
	}

	switch (i) {                            /* JT[3] @ 0x1c04 (min 0, max 5) */
	case 0:
		if (jt41(member, 38, &eff)) {
			l18fa((unsigned char *)eff, &ev, &eb);
			if (val <= 18 && base < 100) {
				ev = (unsigned char)(ev + val);
				if (ev > 18) {
					if (m[159] || m[160] || m[161] || m[158]) {
						short d = (short)((ev - 18) * 10);
						eb = (unsigned char)(m[124] + d);
						if (eb > 100) eb = 100;
					}
					ev = 18;
				}
			}
			l19b2(&base, &eb, &val, &ev);
		}
		if (jt41(member, 113, &eff)) {
			l18fa((unsigned char *)eff, &ev, &eb);
			l19b2(&base, &eb, &val, &ev);
		}
		if (jt41(member, 12, &eff)) {
			l18fa((unsigned char *)eff, &ev, &eb);
			l19b2(&base, &eb, &val, &ev);
		}
		m[113] = val;
		m[124] = base;
		break;

	case 1:
	case 2:
		if (jt41(member, 68, &eff))
			val = 3;
		m[113 + i * 2] = val;
		break;

	case 4: {
		unsigned char oldhp = m[129];
		unsigned char acc = 0;
		unsigned char count = 0;
		short cls;

		m[129] = m[184];
		for (cls = 0; cls <= 6; cls++) {
			unsigned char cv = (m + cls)[164];
			unsigned char cap;
			if (cv > 0)
				l19f8(cls, cv, &acc, &val);
			cv = (m + cls)[157];
			if (cv > 0)
				count++;
			cap = g_a5_buf(-23007)[cls];
			if (cv > cap)
				cv = cap;
			if (cv > m[138]) {
				cv = (unsigned char)(cv - m[138]);
				l19f8(cls, cv, &acc, &val);
			}
		}
		if (count != 0)                 /* asm divuw; count>=1 for a real char */
			acc = (unsigned char)((unsigned short)acc / count);
		m[129] = (unsigned char)(m[129] + acc);
		if (m[129] > oldhp && m[395] != 0)
			m[395] = (unsigned char)(m[395] + (m[129] - oldhp));
		if (m[129] < oldhp && m[395] != 0) {
			short loss = (short)(oldhp - m[129]);
			if (m[395] > loss)
				m[395] = (unsigned char)(m[395] - loss);
			else
				m[395] = 0;
		}
		m[121] = val;
		if (m[121] >= 20)
			jt876(member, 62, 60, 255, 1);
		else
			jt878(member, 62, 0);
		break;
	}

	case 5:
		if (jt41(member, 14, &eff))
			val = (unsigned char)(val + ((unsigned char *)eff)[4]);
		m[123] = val;
		break;

	default:                                /* case 3 etc.: nothing */
		break;
	}
}
/* ====================================================================
 * jt521 area-map render tree (CODE 14). jt521 draws the overland/area
 * map view centred on the party; these leaf helpers do the map-cell and
 * bounds lookups it builds on. The live map row stride is 50 cells.
 * ==================================================================== */

/* L6520 (CODE 14 + 0x6520) — is a (dx,dy) within the 0..6 viewport window? */
static short l6520(short a, short b) __attribute__((unused));
static short l6520(short a, short b)
{
	PROBE("L6520");
	if ((signed char)a >= 0 && (signed char)a <= 6
	 && (signed char)b >= 0 && (signed char)b <= 6)
		return 1;
	return 0;
}

/* L62ec (CODE 14 + 0x62ec) — fetch a map cell at (x,y): the terrain byte from
 * the g_a5_26922 grid into *out_a and the feature byte (cell+9 of the live map
 * g_a5_25318) into *out_b; both 0 when out of the 50x25 bounds. */
static void l62ec(short x, short y, unsigned char *out_a,
                  unsigned char *out_b) __attribute__((unused));
static void l62ec(short x, short y, unsigned char *out_a, unsigned char *out_b)
{
	PROBE("L62ec");
	if ((signed char)x < 0 || (signed char)x > 49
	 || (signed char)y < 0 || (signed char)y > 24) {
		*out_a = 0;
		*out_b = 0;
	} else {
		unsigned char *base = (unsigned char *)(uintptr_t)g_a5_long(-25318);
		*out_b = base[y * 50 + x + 9];
		*out_a = g_a5_buf(-26922)[y * 50 + x];
	}
}

/* L5d92 (CODE 14 + 0x5d92) — look up a directional step in the g_a5_27540
 * move table (row a*12, entry b*2): the two bytes into *out_c/*out_d; returns
 * 1 when the step is walkable (*out_c >= 0). a==0 means "no move" -> 0. */
static short l5d92(short a, short b, unsigned char *out_c,
                   unsigned char *out_d) __attribute__((unused));
static short l5d92(short a, short b, unsigned char *out_c, unsigned char *out_d)
{
	unsigned char *p;

	PROBE("L5d92");
	if ((a & 0xff) == 0)
		return 0;
	p = g_a5_buf(-27540) + (a & 0xff) * 12 + (b & 0xff) * 2;
	*out_c = p[0];
	*out_d = p[1];
	return ((signed char)*out_c >= 0) ? 1 : 0;
}

/* JT[515] / L6c22 (CODE 14 + 0x6c22) — scan the six combat-grid directions out
 * of `entity`'s cell for the best adjacent target/feature (used by the effect
 * applicator jt879). For each direction j the step vector (l5d92) plus the
 * featIdx offset tables (g_a5_-27862 x / g_a5_-27853 y) give a target cell;
 * l62ec resolves its occupant + feature. Writes through three byte out-params:
 *   *outA = an adjacent occupant cell (when present and not the actor's own),
 *   *outC = the feature if it is a door (27/28/29),
 *   *outB = the highest-priority (g_a5_-27848 table) non-zero feature seen,
 *           initialised to 23 and latched to 0 once a direction yields none. */
static void jt515(long entity, short featIdx,
                  unsigned char *outA, unsigned char *outB, unsigned char *outC)
{
	unsigned char *combat;
	short zone, j;
	unsigned char basex, basey, prio;

	PROBE("L6c22");
	*outA = 0;
	*outB = 23;
	prio  = 1;
	*outC = 0;

	zone   = (unsigned char)jt519(entity);
	combat = g_a5_buf(-27472) + zone * 6;
	basex  = combat[1];
	basey  = combat[3];

	for (j = 0; j <= 5; j++) {
		unsigned char dx, dy, occ, feat, txb, tyb;

		combat = g_a5_buf(-27472) + zone * 6;
		if (l5d92((short)combat[5], j, &dx, &dy) == 0)
			continue;                       /* direction not valid */

		txb = (unsigned char)((signed char)dx + (signed char)basex
		    + (signed char)g_a5_buf(-27862)[(unsigned char)featIdx]);
		tyb = (unsigned char)((signed char)dy + (signed char)basey
		    + (signed char)g_a5_buf(-27853)[(unsigned char)featIdx]);

		l62ec((signed char)txb, (signed char)tyb, &occ, &feat);
		if (occ == (unsigned char)zone)
			occ = 0;
		if (occ != 0)
			*outA = occ;
		if (feat == 27 || feat == 28 || feat == 29)
			*outC = feat;

		if (feat == 0) {
			*outB = 0;
			continue;
		}
		if (*outB != 0) {                       /* still scanning */
			unsigned char p = g_a5_buf(-27848)[feat * 4];
			if (p < prio)
				continue;
			prio  = p;
			*outB = feat;
		}
	}
}

/* JT[524] / L61ae (CODE 14 + 0x61ae) — rebuild the 50x25 combat occupancy
 * grid (g_a5_26922): clear it (jt65), then for every active actor record
 * (g_a5_27472, 6 bytes: x word @0, y word @2, facing @5) stamp the actor
 * index into each cell of its facing footprint (the l5d92 step offsets off
 * the map position), and refresh its on-screen cell (g_a5_27059/g_a5_26991
 * = world position minus the scroll origin in the live-map header). */
static void jt524(void) __attribute__((unused));
static void jt524(void)
{
	short i, j;

	PROBE("L61ae");
	jt65((long)(uintptr_t)g_a5_buf(-26922), 1250);
	for (i = 1; i <= (unsigned char)g_a5_byte(-27468); i++) {
		unsigned char *ent = g_a5_buf(-27472) + i * 6;
		unsigned char *scroll;

		if (ent[5] == 0)
			continue;                       /* not on the field */
		for (j = 0; j <= 5; j++) {
			unsigned char dx, dy;

			if (l5d92((short)ent[5], j, &dx, &dy) == 0)
				continue;
			g_a5_buf(-26922)[((signed char)dy + *(short *)(ent + 2)) * 50
			               +  (signed char)dx + *(short *)ent]
				= (unsigned char)i;
		}
		scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
		g_a5_buf(-27059)[i] =
			(unsigned char)(*(short *)ent       - *(short *)(scroll + 2));
		g_a5_buf(-26991)[i] =
			(unsigned char)(*(short *)(ent + 2) - *(short *)(scroll + 4));
	}
}

/* JT[530] / L73cc (CODE 14 + 0x73cc) — stage a combat-status redraw of
 * `entity` in the live-map header (g_a5_25318): byte 6 = `c`, byte 7 = the
 * actor's facing; when scroll-into-view (g_a5_22626) is on, recentre the
 * map on the actor (jt521 mode `b`, dir 8); then leave the header bytes in
 * the post-update state (6 = 0, 7 = 1). */
static void jt530(long entity, short b, short c) __attribute__((unused));
static void jt530(long entity, short b, short c)
{
	unsigned char *hdr = (unsigned char *)(uintptr_t)g_a5_long(-25318);
	unsigned char zone;

	PROBE("L73cc");
	hdr[6] = (unsigned char)c;
	zone   = (unsigned char)jt519(entity);
	hdr[7] = g_a5_buf(-27472)[zone * 6 + 5];

	if (g_a5_byte(-22626) != 0) {
		unsigned char j525 = jt525(entity);
		unsigned char j531 = jt531(entity);

		jt521((signed char)j525, (signed char)j531,
		      (short)(unsigned char)b, 8);
	}
	hdr[6] = 0;
	hdr[7] = 1;
}

/* JT[526] (CODE 14 + 0x71aa) — place a combatant onto the combat map
 * at (x, y): outside the combat view it trivially succeeds; otherwise
 * the actor's combat-state record gets its facing (rec[130] & 127) and
 * position, jt515 vets the destination (own-cell occupant must be
 * empty, the feature must exist and not be the 255 sentinel in the
 * -27848 priority table) — on failure the facing is cleared and 0
 * returned. With `flag` set and the effect sub-record's byte 21 clear,
 * the actor's corpse event records are wiped (jt399) and the cell
 * feature under them restored unless another event still covers the
 * cell. Always rebuilds the occupancy grid (jt524). */
static unsigned char jt526(long entity, short x, short y, short flag)
                                                __attribute__((unused));
static unsigned char jt526(long entity, short x, short y, short flag)
{
	unsigned char *rec = (unsigned char *)(uintptr_t)entity;
	unsigned char *st, *sub;
	unsigned char result = 0, zone, oa, ob, oc, found, i;

	PROBE("jt526");
	if ((unsigned char)g_a5_byte(-27990) != 5)
		return 1;
	zone = (unsigned char)jt519(entity);
	st = g_a5_buf(-27472) + zone * 6;
	st[5] = (unsigned char)(rec[130] & 127);
	*(short *)(st + 0) = (short)(unsigned char)x;
	*(short *)(st + 2) = (short)(unsigned char)y;
	jt515(entity, 8, &oa, &ob, &oc);
	if (oa != 0 || ob == 0 || g_a5_buf(-27848)[ob * 4] == 255) {
		st = g_a5_buf(-27472) + zone * 6;
		st[5] = 0;
		return 0;
	}
	result = 1;
	if ((unsigned char)flag != 0) {
		sub = *(unsigned char **)(uintptr_t)(rec + 64);
		if (sub[21] == 0) {
			for (i = 1; i <= (unsigned char)g_a5_byte(-25320);
			     i++) {
				unsigned char *er =
					g_a5_buf(-25410) + i * 10;
				if (*(long *)er != entity)
					continue;
				if (er[8] != 31)
					ob = er[8];
				jt399(er, 10, 0);
			}
			found = 0;
			for (i = 1; i <= (unsigned char)g_a5_byte(-25320);
			     i++) {
				unsigned char *er =
					g_a5_buf(-25410) + i * 10;
				if (*(long *)er != 0 &&
				    (short)(unsigned char)x ==
						*(short *)(er + 4) &&
				    (short)(unsigned char)y ==
						*(short *)(er + 6))
					found = 1;
			}
			if (found == 0) {
				unsigned char *cell =
					(unsigned char *)(uintptr_t)
					(g_a5_long(-25318) +
					 (unsigned char)y * 50 +
					 (unsigned char)x);
				cell[9] = ob;
			}
		}
	}
	jt524();
	return result;
}

static void jt490(void);

/* JT[874] (CODE 18 + 0x24f8) — raise/return a combatant to the fight:
 * place it back on the map at its own cell (jt526); on success clear
 * the status, set in-combat, seed the HP, stage the redraw (jt530 with
 * scroll-into-view forced on), announce via jt503 and recount the
 * sides (jt490). Returns 1 when placed. */
static unsigned char jt874(long entity, short hp, long msg)
                                                __attribute__((unused));
static unsigned char jt874(long entity, short hp, long msg)
{
	unsigned char *rec = (unsigned char *)(uintptr_t)entity;
	unsigned char x, y, saved;

	PROBE("jt874");
	x = jt525(entity);
	y = jt531(entity);
	if (jt526(entity, (short)(signed char)x, (short)(signed char)y,
		  1) == 0)
		return 0;
	rec[94]  = 0;
	rec[382] = 1;
	rec[395] = (unsigned char)hp;
	if ((unsigned char)g_a5_byte(-27990) == 5) {
		saved = (unsigned char)g_a5_byte(-22626);
		g_a5_byte(-22626) = 1;
		jt530(entity, 3, 0);
		g_a5_byte(-22626) = saved;
	}
	jt503(entity, 1, msg);
	jt490();
	return 1;
}

/* L744e (CODE 14 + 0x744e) — set the map-view clip rectangle: the native
 * 24..248 box in render mode 3, else the doubled-space 8004..8088 box. */
