static long l05dc(void) { PROBE("L05dc"); return g_a5_long(-3076) & ~1L; }

/* JT[1192] (CODE 4 + 0x08ea) — pattern fill: stamp `rows` rows x `wbytes`
 * bytes of the 16-word dither pattern `pat` at the word-aligned GLIB cursor
 * (L05dc), starting at pattern row (idx & 15) and cycling row-by-row; rows
 * advance by the -3084 stride, and the cursor lands one stride past the
 * last row (same convention as jt1202). */
static void jt1192(short rows, short wbytes, const short *pat,
                   short idx) __attribute__((unused));
static void jt1192(short rows, short wbytes, const short *pat, short idx)
{
	long   stride = g_a5_long(-3084);
	short *dst;
	short  r, k, words, pi;

	PROBE("jt1192");
	l05ea(rows, wbytes);
	dst   = (short *)(uintptr_t)l05dc();
	pi    = (short)((idx & 15) * 2);
	words = (short)((wbytes >> 1) - 1);
	for (r = (short)(rows - 1); r >= 0; r--) {
		short *row = dst;
		short  v   = *(const short *)((const char *)pat + pi);

		for (k = words; k >= 0; k--)
			*dst++ = v;
		pi  = (short)((pi + 2) & 30);
		dst = (short *)((char *)row + stride);
	}
	g_a5_long(-3076) = (long)(uintptr_t)dst;
}

/* JT[1194] (CODE 4 + 0x10a8) — table-driven bit-stream decoder: emit `count`
 * bytes into `dst` from the bit stream at `src`, decoding through `table`
 * (256-byte symbol bank + 256-byte control bank per level). A control byte
 * with bit 7 set un-emits the symbol, hops 512 bytes to the next table
 * level (consuming its low-nibble bit count) and extends the loop by one;
 * otherwise the control byte IS the bit count and the level resets. The
 * 16-bit window refills a byte at a time (d5 = bits left in the low byte).
 * Returns the address of the last consumed source byte. */
static long jt1194(const unsigned char *src, unsigned char *dst,
                   short count, const unsigned char *table)
                   __attribute__((unused));
static long jt1194(const unsigned char *src, unsigned char *dst,
                   short count, const unsigned char *table)
{
	unsigned short win;             /* d6 — the bit window */
	short          left = 8;        /* d5 — bits left in the low byte */
	short          bank = 0;        /* d4 — table level | window high byte */
	short          n;               /* d7 */
	long           ret;

	PROBE("jt1194");
	win = (unsigned short)((unsigned short)*src++ << 8);
	win = (unsigned short)(win | *src++);

	n = (short)(count - 1);
	do {
		unsigned char ctl;
		short         take;

		bank = (short)((bank & 0xff00) | ((win >> 8) & 0xff));
		*dst++ = table[bank];
		bank   = (short)(bank + 256);
		ctl    = table[bank];
		if (ctl & 0x80) {               /* extend: deeper table level */
			dst--;
			bank = (short)(bank + 256);
			n++;
			take = (short)(ctl & 15);
		} else {
			bank = 0;
			take = (short)ctl;
		}
		if (take >= left) {             /* refill across the byte seam */
			win   = (unsigned short)(win << left);
			win   = (unsigned short)(win | *src++);
			take  = (short)(take - left);
			win   = (unsigned short)(win << take);
			left  = (short)(8 - take);
		} else {
			win   = (unsigned short)(win << take);
			left  = (short)(left - take);
		}
	} while (--n >= 0);                     /* dbf d7 */

	ret = (long)(uintptr_t)(src - 1);
	if (left == 8)
		ret--;
	return ret;
}

/* JT[1177] = L053e (CODE 4 + 0x053e) — seed the GLIB blit cursor at
 * (row, col): caches the pair in -3080/-3078 and points -3076 at
 * base + (rowbytes >> depth-shift) * row + (col >> depth-shift).
 *
 * The Mac reads the page base from the -2570 page-descriptor record
 * (colour: entry+2 handle deref; mono: entry+2 direct) — the port
 * never populates those GrafPorts (jt1128 page flips are presents,
 * ADR-0003/0005), so the base comes from the shim's screen back
 * buffer (qd_screen_pixels). This un-stubs every -3076 consumer:
 * the jt119/jt122 save-under pair, jt1192/jt1194/jt1197/jt1202, and
 * the jt1126 scroll below. The mulsw product keeps only its low 16
 * bits on the Mac (swap/clrw/swap) — 320*200 fits, kept faithful. */
static void jt1177(short row, short col)
{
	unsigned char *px = NULL;
	short          rb, sw, sh;
	long           base, shift;

	PROBE("jt1177");
	g_a5_word(-3080) = row;
	g_a5_word(-3078) = col;
	if (!qd_screen_pixels(&px, &rb, &sw, &sh) || px == NULL)
		return;                 /* no surface — leave the cursor */
	shift = l04f0();
	base  = (long)(uintptr_t)px;
	base += (long)(unsigned short)(((short)(l04de() >> shift)) * row);
	base += (long)(col >> shift);
	g_a5_long(-3076) = base;
}

/* jt1126 (CODE 4 + 0x5d9c) — the page SCROLL-BLIT: move the rect
 * (v1,h1)-(v2,h2) by (dv,dh) within the current page and fill the
 * exposed strips with `fill` (skipped when fill < 0), then InvalRect
 * the whole rect. Callers: the CODE 7 message-window scroll and the
 * CODE 8 design editor.
 *
 * Faithful flow: jt1135 maps both corners, jt1141 maps the deltas
 * (then dv/dh = corner - mapped, the negated pixel delta), the
 * corners are ordered, and the COLOUR path row-copies via the
 * jt1177 cursor + JT[406] (memmove), walking up or down by the sign
 * of dv so overlapping moves stay safe; the exposed strips fill via
 * JT[1161] and the (possibly doubled, -2346) rect invalidates.
 *
 * PORT notes: the Mac brackets the copy with SetPort(page[-2352]) +
 * GetCTable/RGBForeColor(black)/RGBBackColor(white) and restores the
 * port after — elided (single shim surface, identity palette). The
 * MONO path (-2347 == 0) builds two rects via JT[397]/JT[413] and
 * _CopyBits them — dead in the port (colour is permanent), kept as
 * a PROBE marker. */
static void jt1126(short v1, short h1, short v2, short h2,
                   short dv, short dh, short fill) __attribute__((unused));
static void jt1126(short v1, short h1, short v2, short h2,
                   short dv, short dh, short fill)
{
	short lo_v, lo_h;               /* fp@(-42) / fp@(-44) */
	short src_col, dst_col, span;   /* fp@(-50) / fp@(10) / fp@(-56) */
	short srow, drow;
	Rect  r;

	PROBE("jt1126");
	l4d88();
	jt1135(v1, h1, &v1, &h1);
	jt1135(v2, h2, &v2, &h2);
	jt1141(v1, h1, dv, dh, &dv, &dh);
	dv = (short)(v1 - dv);
	dh = (short)(h1 - dh);

	if (v1 < v2) {
		lo_v = v1;
	} else {
		lo_v = v2;
		v2   = v1;
	}
	if (h1 < h2) {
		lo_h = h1;
	} else {
		lo_h = h2;
		h2   = h1;
	}

	if (g_a5_byte(-2347) != 0) {
		/* the colour row-copy path (the port's live one) */
		long sh = l04f0();

		if (dh < 0) {
			src_col = (short)(lo_h - dh);
			dst_col = lo_h;
			span    = (short)((h2 >> sh) - (src_col >> sh));
		} else {
			src_col = lo_h;
			dst_col = (short)(lo_h + dh);
			span    = (short)((h2 >> sh) - (dst_col >> sh));
		}
		if (dv < 0) {
			for (srow = (short)(lo_v - dv), drow = lo_v;
			     srow < v2; srow++, drow++) {
				long src;

				jt1177(srow, src_col);
				src = g_a5_long(-3076);
				jt1177(drow, dst_col);
				jt406((void *)(uintptr_t)g_a5_long(-3076),
				      (const void *)(uintptr_t)src, span);
			}
		} else {
			srow = (short)(v2 - dv);
			drow = v2;
			while (--srow >= lo_v) {
				long src;

				drow--;
				jt1177(srow, src_col);
				src = g_a5_long(-3076);
				jt1177(drow, dst_col);
				jt406((void *)(uintptr_t)g_a5_long(-3076),
				      (const void *)(uintptr_t)src, span);
			}
		}
	} else {
		/* mono _CopyBits arm — dead in the port (colour mode is
		 * permanent; the -2570 GrafPort BitMaps aren't modelled). */
		PROBE("jt1126: mono CopyBits arm (dead)");
	}

	if (fill >= 0) {
		if (dv < 0)
			jt1161((short)(v2 + dv), lo_h, v2, h2, fill);
		else if (dv > 0)
			jt1161(lo_v, lo_h, (short)(lo_v + dv), h2, fill);
		if (dh < 0)
			jt1161(lo_v, (short)(h2 + dh), v2, h2, fill);
		else if (dh > 0)
			jt1161(lo_v, lo_h, v2, (short)(lo_h + dh), fill);
	}

	r.top    = lo_v;
	r.left   = lo_h;
	r.bottom = v2;
	r.right  = h2;
	if (l5d8c() != 0) {
		if (g_a5_byte(-2346) != 0) {
			r.top    = (short)(r.top    << 1);
			r.left   = (short)(r.left   << 1);
			r.bottom = (short)(r.bottom << 1);
			r.right  = (short)(r.right  << 1);
		}
		InvalRect(&r);
	}
}

