/* JT[501] (CODE 13 + 0x1a24) — animated area-map line / region renderer.
 * Walks a Bresenham line (built into the buf148 direction list via l6eba/l6f68)
 * between the clamped endpoints (x1,y1)-(x2,y2), scrolling the viewport
 * (g_a5_25318) to keep the line on screen and drawing an animated `77+frame`
 * glyph (g_a5_27866) along it.  `animMax` is the frame-cycle length and `delay`
 * the per-step dwell (jt476, x2).  Used for targeting cursors / trajectory
 * lines / AoE outlines on the overland & area maps.  Frame layout: buf148 is
 * the per-step direction list, desc24 the line descriptor; the rest are the
 * running anchor (x1,y1), scroll center (ctrX,ctrY), sub-cell accumulators
 * (accX,accY) and screen sub-coordinates (sx,sy, in thirds-of-a-cell). */
static void jt501(short x1, short y1, short x2, short y2,
                  short animMax, short delay) __attribute__((unused));
static void jt501(short x1, short y1, short x2, short y2,
                  short animMax, short delay)
{
	unsigned char buf148[148];
	unsigned char desc24[24];
	unsigned char *scroll;
	short count, len, anim, needRefresh, edge;
	short ctrX, ctrY, accX, accY, dx, dy, stepDX, stepDY, sx, sy, tmp;

	PROBE("jt501");

	/* Phase 0 — clamp endpoints to the 50x25 area-map grid. */
	if (x1 < 0) x1 = 0; else if (x1 > 49) x1 = 49;
	if (y1 < 0) y1 = 0; else if (y1 > 24) y1 = 24;
	if (x2 < 0) x2 = 0; else if (x2 > 49) x2 = 49;
	if (y2 < 0) y2 = 0; else if (y2 > 24) y2 = 24;

	/* Phase 1 — build the per-step direction list (in thirds of a cell). */
	jt399(buf148, 148, 8);
	jt399(desc24, 24, 0);
	count = 0;
	anim  = 0;
	*(short *)(desc24 + 0) = (short)(x1 * 3);
	*(short *)(desc24 + 2) = (short)(y1 * 3);
	*(short *)(desc24 + 4) = (short)(x2 * 3);
	*(short *)(desc24 + 6) = (short)(y2 * 3);
	l6eba(desc24);
	do {
		edge = (l6f68(desc24) == 0) ? 1 : 0;
		buf148[count++] = desc24[23];
	} while (edge == 0);
	if ((unsigned char)count < 4)
		return;
	len = (short)(count - 2);

	/* Phase 2 — choose the scroll center: midpoint when both endpoints are on
	 * screen (or the span is small), else the viewport-relative +3 cell. */
	dx = (short)(x2 - x1);
	dy = (short)(y2 - y1);
	scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
	if (l6520((short)(x1 - *(short *)(scroll + 2)),
	          (short)(y1 - *(short *)(scroll + 4))) &&
	    l6520((short)(x2 - *(short *)(scroll + 2)),
	          (short)(y2 - *(short *)(scroll + 4)))) {
		needRefresh = 1;                                /* L1c18 — both in */
		ctrX = (short)(*(short *)(scroll + 2) + 3);
		ctrY = (short)(*(short *)(scroll + 4) + 3);
	} else if (jt388(dx) <= 6 && jt388(dy) <= 6) {
		needRefresh = 1;                                /* L1bca — small span */
		ctrX = (short)(dx / 2 + x1);
		ctrY = (short)(dy / 2 + y1);
	} else {
		needRefresh = 0;                                /* L1bf6 — off-window */
		ctrX = (short)(*(short *)(scroll + 2) + 3);
		ctrY = (short)(*(short *)(scroll + 4) + 3);
	}
	jt521(ctrX, ctrY, 255, 8);
	count = 0;
	accX  = 0;
	accY  = 0;

	/* Phase 3 — drive the animation.  Each outer pass walks the line from the
	 * running anchor; if it runs off the window it walks back from the far
	 * endpoint, scrolling the viewport, and the loop repeats (needRefresh==0)
	 * until the whole line fits. */
	for (;;) {
		scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
		sx = (short)((short)((x1 - *(short *)(scroll + 2)) * 3) + accX);
		sy = (short)((short)((y1 - *(short *)(scroll + 4)) * 3) + accY);
		edge = 0;

		/* forward walk */
		do {
			unsigned char dir = buf148[count];
			stepDX = (signed char)g_a5_buf(-27862)[dir];
			stepDY = (signed char)g_a5_buf(-27853)[dir];
			sx = (short)(sx + stepDX);
			sy = (short)(sy + stepDY);

			if (delay != 0 || (sx % 3) == 0 || (sy % 3) == 0) {
				jt112(2);
				tmp = l1944(sy);
				jt119(tmp, l1972(sx), 12, 12);
				l19a0(sx, sy, (short)(77 + anim), 5, g_a5_long(-27866));
				jt476((short)(delay * 2));
				tmp = l1944(sy);
				jt122(tmp, l1972(sx), 12, 12);
				if (++anim >= animMax)
					anim = 0;
				jt112(0);
			}
			count++;

			if (sx < 0 || sx > 18 || sy < 0 || sy > 18)
				edge = 1;

			if (edge == 0 && (unsigned char)count < (unsigned char)len) {
				accX = (short)(accX + stepDX);
				accY = (short)(accY + stepDY);
				if (jt388(accX) == 3) {
					x1   = (short)(x1 + l6d1e(accX));
					ctrX = (short)(ctrX + l6d1e(accX));
					accX = 0;
				}
				if (jt388(accY) == 3) {
					y1   = (short)(y1 + l6d1e(accY));
					ctrY = (short)(ctrY + l6d1e(accY));
					accY = 0;
				}
			}
		} while ((unsigned char)count < (unsigned char)len && edge == 0);

		if ((unsigned char)count >= (unsigned char)len) {
			/* L20d8 — line fully traversed: draw the final endpoint. */
			needRefresh = 1;
			scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
			if (!l6520((short)(x2 - *(short *)(scroll + 2)),
			           (short)(y2 - *(short *)(scroll + 4))))
				jt521(x2, y2, 3, 8);
			scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
			sx = (short)((x2 - *(short *)(scroll + 2)) * 3);
			sy = (short)((y2 - *(short *)(scroll + 4)) * 3);
			tmp = l1944(sy);
			jt119(tmp, l1972(sx), 12, 12);
			l19a0(sx, sy, (short)(77 + anim), 5, g_a5_long(-27866));
			if (delay != 0) {
				jt117();
				jt476((short)(delay * 2));
				tmp = l1944(sy);
				jt122(tmp, l1972(sx), 12, 12);
			}
		} else {
			/* L1ea2 — hit the window edge: walk back from the far endpoint,
			 * scrolling the viewport to follow. */
			short adjX = 0, adjY = 0;
			accY = 0;
			accX = 0;
			x1 = x2;
			y1 = y2;
			if (x2 + 3 > 49)      adjX = (short)(x2 - 49);
			else if (x2 < 3)      adjX = (short)(3 - x2);
			if (y2 + 3 > 24)      adjY = (short)(y2 - 24);
			else if (y2 < 3)      adjY = (short)(3 - y2);
			ctrX = (short)(x2 + adjX);
			ctrY = (short)(y2 + adjY);
			jt521(ctrX, ctrY, 255, 8);
			scroll = (unsigned char *)(uintptr_t)g_a5_long(-25318);
			sx = (short)((x2 - *(short *)(scroll + 2)) * 3);
			sy = (short)((y2 - *(short *)(scroll + 4)) * 3);
			count = len;
			edge  = 0;

			do {
				unsigned char dir = buf148[count];
				stepDX = (short)-(signed char)g_a5_buf(-27862)[dir];
				stepDY = (short)-(signed char)g_a5_buf(-27853)[dir];
				sx = (short)(sx + stepDX);
				sy = (short)(sy + stepDY);

				if (sx > 18)      x1 = (short)(*(short *)(scroll + 2) + 6);
				else if (sx < 0)  x1 = *(short *)(scroll + 2);
				if (sy > 18)      y1 = (short)(*(short *)(scroll + 4) + 6);
				else if (sy < 0)  y1 = *(short *)(scroll + 4);

				if (sx < 0 || sx > 18 || sy < 0 || sy > 18)
					edge = 1;

				if (edge == 0) {
					accX = (short)(accX + stepDX);
					accY = (short)(accY + stepDY);
					if (jt388(accX) == 3) {
						x1   = (short)(x1 + l6d1e(accX));
						ctrX = (short)(ctrX + l6d1e(accX));
						accX = 0;
					}
					if (jt388(accY) == 3) {
						y1   = (short)(y1 + l6d1e(accY));
						ctrY = (short)(ctrY + l6d1e(accY));
						accY = 0;
					}
					count--;
				}
			} while (edge == 0);
		}

		/* L21dc — refresh and finish, or loop again until the line fits. */
		if (needRefresh != 0) {
			jt117();
			return;
		}
	}
}
/* JT[1199] (CODE 4+0x22aa) — byte-swap a long (endian reverse; the
 * design/save data is little-endian on disk). */
static long   jt1199(long v)
{
	PROBE("jt1199");
	return (long)(((unsigned long)v << 24)
	            | (((unsigned long)v & 0xff00UL) << 8)
	            | (((unsigned long)v & 0xff0000UL) >> 8)
	            | ((unsigned long)v >> 24));
}

/* Globals case 2 manages. */
/* g_a5_18844 → macro (data_pool replay buffer) */
/* g_a5_18882 → macro (data_pool replay buffer) */
/* g_a5_27946 / g_a5_27982 are now macros in the L5124 cluster at the
 * top of the file. */

/* Globals cases 7..11 manage. */
/* g_a5_27988 → macro (data_pool replay buffer) */
/* g_a5_14284 → macro (data_pool replay buffer) */
/* g_a5_18472 → macro (data_pool replay buffer) */
/* Forward — jt19 / jt159 land further down with the case 7..11 stubs. */
static void jt19(short a, short b);
static int  jt159(const char *prompt, short b);

/* L12a0 — View Character dispatcher. CODE 12 + 0x12a0. ~800 bytes of
 * asm that opens a 22x38 window via JT[103], pumps the input loop via
 * JT[179], runs a JT[3] sub-dispatch over the user's key (Escape →
 * exit, Enter → confirm, others case-by-case), then walks the design
 * list via JT[589] / JT[488] / JT[384] / JT[169]. Stays a PROBE stub —
 * lifting the full body needs the CODE 7 dialog runtime first. */
/* L12a0 (CODE 12 + 0x12a0) — View Character dispatcher.
 *
 *   1. Open the 38x22 window via JT[103]; pump events JT[179](2).
 *   2. Clear the input byte fp[-30]; map Escape (27) to 2 when
 *      g_a5_24139 != 0 so the dispatcher classifies it consistently.
 *   3. JT[3] dispatches on fp[-30]: case 0 → g_a5_22733 = 1, case 1
 *      → g_a5_22733 = 2, default → g_a5_22733 = 1 (Mac inline post-
 *      call table 0x000c / 0x02ea).
 *   4. Iterate: JT[589](0, &fp[-8], &fp[-4]) primes the list head;
 *      bail to JT[581] when fp[-4] is null. Walk the iter — for
 *      every match against L1266 sprintf "* %s" + JT[384] so the
 *      entry is rendered with the marker.
 *   5. JT[179](1) then JT[169](handles, dims, head, 1, 0, &flag,
 *      &idx, &iter) returns the user's key in fp[-30]. Escape (27)
 *      maps to 1 (exit).
 *   6. If the key is null and the entry isn't marked '*': JT[477]
 *      reserves the design slot (fp[-20]) at tag 398 from
 *      g_a5_22212; JT[165] fills fp[-16]. JT[587] cleans the source
 *      slot, then "* %s" via JT[488] + JT[384] paints the marker.
 *      An inner walk over g_a5_27928 counts characters whose
 *      entry[147] flag is below 0x80 (fp[-28]) and entry[161] is
 *      non-zero (fp[-29]) so the "rangers in party" / "5 max"
 *      checks at L1562 can fire — bail with JT[42](...) on overflow.
 *      JT[590] + JT[593](1) commit; JT[471](fp[-20]) tears down.
 *   7. Loop exit when fp[-30] == 1 OR (fp[-28] < 5 AND the design
 *      record's count at +32 < 7). JT[581] cleans up.
 *
 * Like L15e2, the inner add-character arm leaves the heavy work
 * (entry-count walk, "too many rangers" message) PROBE-deferred —
 * the lift records the outer call sequence and the cap conditions
 * resolve once the right slot fields land. */
static void l12a0(void)
{
	long  head = 0;
	long  tail = 0;
	long  entry;
	long  matched;
	short input = 0;
	short idx   = 0;
	short body_count   = 0;
	unsigned char loop_flag = 0;
	unsigned char fresh_slot[64];

	PROBE("L12a0");

	jt103(1, 1, 38, 22);
	jt179(2);

	if (g_a5_24139 != 0 && input == 27)
		input = 2;

	/* Inline JT[3] table at CODE 12 + 0x12ea: min=0 max=2,
	 * default → g_a5_22733 = 1; arm 0 → g_a5_22733 = 1; arm 1 →
	 * g_a5_22733 = 2; arm 2 jumps past the main loop to L15de
	 * (clean exit). Lifted as a direct C switch — input is always
	 * 0 on the first pass (the Escape-to-2 remap above tests an
	 * already-cleared byte), so practically the dispatcher always
	 * sets g_a5_22733 = 1 and proceeds into the loop. */
	switch (input) {
	case 0:
		g_a5_22733 = 1;
		break;
	case 1:
		g_a5_22733 = 2;
		break;
	case 2:
		return;          /* exits to L15de */
	default:
		g_a5_22733 = 1;
		break;
	}

	for (;;) {
		jt589(0, &tail, &head);
		if (head == 0)
			break;

		entry = head;
		while (entry != 0) {
			const unsigned char *e =
				(const unsigned char *)(uintptr_t)entry;
			if (l1266((const char *)&e[5])) {
				const char *prefixed =
					jt488(ua_strs_at(0x5fd4), &e[5]);
					/* "* %s" */
				jt384((char *)(uintptr_t)&e[5], prefixed);
			}
			entry = *(const long *)e;
		}

		loop_flag = 1;
		jt179(1);
		input = (short)jt169(g_a5_13792, g_a5_14216, 1, 2, 38, 22,
		                     head, 1, 0,
		                     &loop_flag, &idx, &entry);
		if (g_a5_24139 != 0 && input == 27)
			input = 1;

		if (input == 0) {
			const unsigned char *e =
				(const unsigned char *)(uintptr_t)entry;

			if (e[5] == '*')
				goto exit_check;

			/* Port: add the picked saved character to the active
			 * party.  The Mac copies the saved record into a fresh
			 * 398-byte party-pool slot (jt477 + jt165 + jt587); the
			 * port's party is the CHAR_INPARTY subset of cg_pool, so
			 * flag the matching slot and relink.  Matched on the raw
			 * name (before the "* " marker is prefixed below). */
			{
				short pi;
				for (pi = 0; pi < cg_pool_count; pi++)
					if (jt396((const char *)&cg_pool[pi][96],
					          (const char *)&e[5]) != 0) {
						cg_pool[pi][CHAR_INPARTY] = 1;
						break;
					}
				cg_party_relink();
				save_roster();
			}

			jt477(&g_a5_22212, 398, fresh_slot);
			matched = jt165(idx, tail);
			jt587(fresh_slot, (void *)(uintptr_t)matched, 0, 1);

			{
				const char *prefixed =
					jt488(ua_strs_at(0x5fda), &e[5]);
					/* "* %s" */
				jt384((char *)(uintptr_t)&e[5], prefixed);
			}

			if (g_a5_27928 == 0) {
				/* Empty roster — commit and stop. */
				unsigned char *handle =
					(unsigned char *)g_a5_28006;
				if (handle != NULL)
					handle[32] = 0;
				jt590(fresh_slot);
				jt593(1);
			} else {
				/* Walk the roster counting body entries;
				 * the "rangers in party" cap at L1562
				 * stays PROBE-deferred — the dispatcher
				 * exits cleanly via L1562 / L159c. */
				body_count = 0;
				jt471(matched, 398, &g_a5_22212);
			}
		}

exit_check:
		{
			const unsigned char *handle =
				(const unsigned char *)g_a5_28006;
			short occupied =
				(handle != NULL) ? (short)handle[32] : 0;
			short exit_now = (input == 1) ||
			                 (body_count < 5 && occupied < 7);
			if (exit_now) {
				jt581(head, tail);
				return;
			}
		}
	}
}

/* JT[488] (CODE 3 + 0x438) — sprintf into the A5 scratch buffer at
 * -10362, returning the buffer address. All format strings the
 * engine uses are `%s` substitutions over a Pascal-string-style
 * name; the lift uses C vsnprintf which handles them faithfully.
 *
 * The buffer is a single shared 256-byte slot in g_a5_below[] —
 * the caller must consume the returned pointer before the next
 * jt488 call, since the next call clobbers it. */

/* stdarg.h / stdio.h moved to the top so jt452 can use va_list too. */

static const char *jt488(const char *fmt, ...)
{
	va_list ap;

	PROBE("jt488");
	if (fmt == NULL)
		fmt = "";
	va_start(ap, fmt);
	vsnprintf(g_a5_10362, G_A5_10362_LEN, fmt, ap);
	va_end(ap);
	return g_a5_10362;
}

/* JT[394] (CODE 3 + 0x4796) — vsprintf into the caller's buffer.
 *
 * The Mac implementation parks the destination pointer in
 * g_a5_9168 and runs THINK C's `_doprintf` core (L3fb8) with a
 * write-character callback (JT[383]) that advances g_a5_9168 byte
 * by byte. After the format walk completes, the function writes a
 * null terminator at the (now post-last-char) g_a5_9168 position.
 *
 * The portable equivalent is plain vsprintf — same semantics, no
 * caller-visible state. Used 156 times across CODE 1..23 for every
 * "build a string for an alert" / "format a stat into a row" etc.
 *
 * The output buffer's size is the caller's responsibility (matches
 * the Mac); engine format strings are STRS-defined templates that
 * never grow large. */
static int jt394(char *buf, const char *fmt, ...) __attribute__((unused));
static int jt394(char *buf, const char *fmt, ...)
{
	va_list ap;
	int     n;

	PROBE("jt394");
	if (buf == NULL)
		return 0;
	if (fmt == NULL)
		fmt = "";
	va_start(ap, fmt);
	n = vsprintf(buf, fmt, ap);
	va_end(ap);
	return n;
}

/* L3e62 (CODE 3 + 0x3e62) — JT[400]'s custom-handler lookup. Scans the
 * handler-set string `set` (e.g. "vka") for conversion char `c`; returns its
 * 1-based position (1='v', 2='k', 3='a' for "vka"), or 0 if absent. The 1-based
 * index selects the matching handler fn from JT[400]'s vararg list (handler #idx
 * sits at fp@(20 + idx*4), i.e. the idx-th vararg after the set string). */
static short l3e62(const char *set, short c) __attribute__((unused));
static short l3e62(const char *set, short c)
{
	short counter = 0;

	if (set == NULL)
		return 0;
	while (*set) {
		counter++;
		if (*set++ == (char)c)
			return counter;
	}
	return 0;
}

/* L3e94 (CODE 3 + 0x3e94) — the recursive unsigned-number emitter at the core
 * of the JT[400] "%r" format VM. Emits `value` in `base` (8/10/16, digits
 * 0-9A-F) through the `emit` callback, left-padded to `width` with '0' (when
 * `zeroflag`) or ' '. Recurses on value/base so the most-significant digit
 * prints first; the padding is emitted once, at the recursion base. Unsigned —
 * the sign ('-' + negate) is the caller's job (JT[400]'s %d arm). First leaf of
 * the JT[400] lift; see docs/jt400-format-vm.md for the full engine map. */
static void l3e94(short value, short width, unsigned char zeroflag,
                  short base, void (*emit)(short)) __attribute__((unused));
static void l3e94(short value, short width, unsigned char zeroflag,
                  short base, void (*emit)(short))
{
	unsigned short v = (unsigned short)value;
	unsigned short b = (unsigned short)base;
	unsigned short digit;

	if (v >= b) {
		l3e94((short)(v / b), (short)(width - 1), zeroflag, base, emit);
	} else {
		short w;
		for (w = (short)(width - 1); w > 0; w--)
			emit(zeroflag ? (short)48 : (short)32);   /* '0' or ' ' pad */
	}
	digit = (unsigned short)(v % b);
	emit((short)(digit <= 9 ? (48 + digit) : (55 + digit)));   /* 0-9 / A-F */
}

/* L3f20 (CODE 3 + 0x3f20) — the LONG analog of l3e94, used by JT[400]'s "%l"
 * arm. Same recursive most-significant-digit-first emitter, but the value is a
 * 32-bit long (the Mac uses JT[5]/JT[6] = unsigned long div/mod; the m68k C
 * compiler emits the equivalent for unsigned-long / and %). Sign is the caller's
 * job (the %l arm negates + emits '-' when the encoded base is odd/signed). */
static void l3f20(long value, short width, unsigned char zeroflag,
                  short base, void (*emit)(short)) __attribute__((unused));
static void l3f20(long value, short width, unsigned char zeroflag,
                  short base, void (*emit)(short))
{
	unsigned long  v = (unsigned long)value;
	unsigned long  b = (unsigned long)(unsigned short)base;
	unsigned long  digit;

	if (v >= b) {
		l3f20((long)(v / b), (short)(width - 1), zeroflag, base, emit);
	} else {
		short w;
		for (w = (short)(width - 1); w > 0; w--)
			emit(zeroflag ? (short)48 : (short)32);   /* '0' or ' ' pad */
	}
	digit = v % b;
	emit((short)(digit <= 9 ? (48 + digit) : (55 + digit)));   /* 0-9 / A-F */
}

/* JT[400] (CODE 3 + 0x3fb8, ~490 instr) — THINK C's "%r" recursive-format VM.
 * NOT a printf: a template-driven accumulator machine that emits characters one
 * at a time through the caller's `emit` callback. `args` is a flat word-stream
 * arg cursor (advanced 2 per word arg, 4 per %s/%l/%r long). Each '%' loads the
 * current arg into a 16-bit accumulator, then parses an optional [0][width] and
 * a stream of operator chars: value arms (d/u/x/X/o/l/s/c/w) format+emit the
 * accumulator; arithmetic arms (+ - * / # \ & | ^ ~ > < =) turn the template
 * into a tiny calculator over the accumulator; group arms (%(..%) repeat,
 * %[..%] indexed select) and %r (recurse on a sub-template) drive control flow.
 * Faithful lift of L3fb8. JT[400] is VARIADIC after the emit sink: the Mac
 * call (L0306) passes jt400(fmt, &args, emit, "vka", h1, h2, h3) — the set
 * string names the custom conversions and the handler fns follow as varargs
 * (handler #idx sits at fp@(20 + idx*4)). The public jt400() reads those into
 * an array and hands them to jt400_run(), which holds the VM. Frame-local names
 * mirror the asm fp-slots. See docs/jt400-format-vm.md. */
typedef void (*jt400_handler)(short acc, short width);

static void jt400_run(char *fmt, void *args, void (*emit)(short),
                      const char *hchars, jt400_handler *hfns, short nh);

static void jt400_run(char *fmt, void *args, void (*emit)(short),
                      const char *hchars, jt400_handler *hfns, short nh)
{
	char          *argp = (char *)args;   /* fp@(-20) arg cursor          */
	short          acc = 0;               /* fp@(-26) accumulator          */
	short          width = 0;             /* fp@(-22) field width          */
	short          operand = 0;           /* fp@(-24) op operand / count   */
	unsigned char  zeroflag = 0;          /* fp@(-1)  '%0N' pad with '0'   */
	short          counter = 0;           /* fp@(-28) %(..%) repeat count  */
	char          *loop_start = NULL;     /* fp@(-10) %( body start        */
	char          *sel_argp = NULL;       /* fp@(-32) %[ saved arg cursor  */
	short          c;                     /* d7 current char               */

	for (;;) {
		c = (unsigned char)*fmt++;            /* L45c0 fetch next char     */
		if (c == 0)
			return;
		if (c != '%') {                       /* L3fcc literal             */
			emit(c);
			continue;
		}
		acc = *(short *)argp;                 /* load current arg word     */

	parse_conv:                                   /* L3fe0 parse [0][width] */
		c = (unsigned char)*fmt++;
		if (c >= '0' && c <= '9') {
			zeroflag = (unsigned char)(c == '0');
			width = (short)(c - '0');
			for (;;) {
				c = (unsigned char)*fmt++;
				if (c < '0' || c > '9')
					break;
				width = (short)(width * 10 + (c - '0'));
			}
			operand = width;              /* L4040 operand = width     */
		} else {
			width = 0;                    /* L4048 no digits           */
			zeroflag = 0;
			operand = 1;
		}
		/* c now holds the operator/conversion char. */

		if (hchars) {                         /* L4056 custom handlers */
			short idx = l3e62(hchars, c);
			if (idx != 0 && idx <= nh) {
				/* handler formats the pre-loaded accumulator;
				 * the asm (0x4080) does NOT advance argp here. */
				hfns[idx - 1](acc, width);
				continue;             /* -> next template char */
			}
		}

	dispatch:                                     /* L4094 standard switch */
		switch (c) {
		/* ---- value arms: format the accumulator, advance argp, done --- */
		case 'd':                             /* 0x4120 signed decimal     */
			if (acc < 0) {
				emit('-');
				width--;
				acc = (short)(-acc);
			}
			/* fall through */
		case 'u':                             /* 0x4140 unsigned decimal   */
			l3e94(acc, width, zeroflag, 10, emit);
			argp += 2;
			break;
		case 'x':                             /* 0x4246 hex (X same arm)   */
		case 'X':
			l3e94(acc, width, zeroflag, 16, emit);
			argp += 2;
			break;
		case 'o':                             /* 0x426e octal              */
			l3e94(acc, width, zeroflag, 8, emit);
			argp += 2;
			break;
		case 's': {                           /* 0x4168 string, right-pad  */
			char *sp = *(char **)argp;
			argp += 4;
			if (sp)
				while (*sp) {
					emit((unsigned char)*sp++);
					width--;
				}
			while (width-- > 0)           /* pad to width with ' '     */
				emit(' ');
			break;
		}
		case 'c':                             /* 0x41c8 char (high,low)    */
			if (width > 1) {
				while (width > 2) {   /* lead NUL pad to width     */
					emit(0);
					width--;
				}
				emit((short)(acc >> 8));
			}
			emit(acc);
			argp += 2;
			break;
		case 'w':                             /* 0x421a word (low,high)    */
			while (width > 2) {
				emit(0);
				width--;
			}
			emit(acc);
			emit((short)(acc >> 8));
			argp += 2;
			break;
		case 'l': {                           /* 0x4296 long modifier      */
			char *lp = argp;              /* fp@(-40) arg snapshot     */
			short base = 11;              /* default: signed decimal   */
			short lc = (unsigned char)*fmt++;
			switch (lc) {                 /* sub-table @ 0x42b2        */
			case 'u': base = 10; break;
			case 'd': base = 11; break;
			case 'x': base = 16; break;
			case 'o': base = 8;  break;
			default:  fmt--;     break;   /* unknown: back up fmt      */
			}
			if (base & 1) {               /* odd base => signed        */
				if (*(long *)lp < 0) {
					emit('-');
					width--;
					*(long *)lp = -*(long *)lp;
				}
			}
			l3f20(*(long *)lp, width, zeroflag,
			      (short)(base & ~1), emit);
			argp = lp + 4;
			break;
		}
		case 'r': {                           /* 0x4344 recursive format   */
			char *sub_fmt  = *(char **)argp; argp += 4;
			void *sub_args = *(void **)argp; argp += 4;
			/* Carry the full handler array across recursion. The Mac
			 * forwards only h1 (0x436a pushes fp@24 alone), leaving
			 * %k/%a inside a %r sub-template reading stack garbage —
			 * a latent bug we decline to reproduce. */
			jt400_run(sub_fmt, sub_args, emit, hchars, hfns, nh);
			break;
		}

		/* ---- arithmetic arms: mutate acc, re-parse next operator ------ */
		case '+': acc = (short)(acc + operand); goto parse_conv;   /* 0x438e */
		case '-': acc = (short)(acc - operand); goto parse_conv;   /* 0x451c */
		case '/': acc = (short)((short)acc / (short)operand);
			  goto parse_conv;                                /* 0x4534 */
		case '#': acc = (short)((short)acc % (short)operand);
			  goto parse_conv;                                /* 0x4546 */
		case '\\': acc = (short)((unsigned short)acc
				       / (unsigned short)operand);
			   goto parse_conv;                               /* 0x4570 */
		case '&': acc = (short)(acc & operand); goto parse_conv;   /* 0x44d4 */
		case '|': acc = (short)(acc | operand); goto parse_conv;   /* 0x455a */
		case '^': acc = (short)(acc ^ operand); goto parse_conv;   /* 0x4528 */
		case '~': acc = (short)(~acc);          goto parse_conv;   /* 0x4564 */
		case '>': acc = (short)(acc >> operand); goto parse_conv;  /* 0x439a */
		case '<': acc = (short)(acc << operand); goto parse_conv;  /* 0x43ac */
		case '=': acc = width;                  goto parse_conv;   /* 0x4580 */
		case '*':                             /* 0x44e0 multiply / *-width */
			if (width != 0) {             /* %N*: acc *= operand       */
				acc = (short)(acc * operand);
				goto parse_conv;
			}
			operand = acc;                /* %*: width from this arg   */
			width = acc;
			argp += 2;
			acc = *(short *)argp;         /* reload acc from next arg  */
			c = (unsigned char)*fmt++;    /* dispatch following char   */
			goto dispatch;

		/* ---- group / control arms ------------------------------------ */
		case '(':                             /* 0x43be %( repeat open     */
			counter = acc;
			loop_start = fmt;
			argp += 2;
			if (counter != 0)
				break;                /* enter body                */
			while (*fmt) {                /* count 0: skip to "%)"     */
				if ((unsigned char)*fmt++ == '%'
				    && *fmt == ')')
					break;
			}
			if (*fmt)
				fmt++;                /* skip ')'                  */
			break;
		case ')':                             /* 0x4408 %) repeat close     */
			counter--;
			if (counter > 0)
				fmt = loop_start;
			break;
		case '[':                             /* 0x441e %[ select open      */
			sel_argp = argp + 2;
			for (;;) {                    /* skip `acc` cases          */
				if (*fmt == 0 || acc <= 0)
					break;
				if ((unsigned char)*fmt++ == '%') {
					short sc = (unsigned char)*fmt++;
					if (sc == ';') {      /* case separator    */
						acc--;
						continue;
					}
					if (sc == ':')        /* selected case     */
						break;
					if (sc == ']') {      /* end of group      */
						argp = sel_argp;
						break;
					}
					/* default: keep scanning */
				}
			}
			break;
		case ']':                             /* 0x4480 %] select close     */
			argp = sel_argp;
			break;
		case ';':                             /* 0x448a %; / %: -> skip to %] */
		case ':':
			while (*fmt) {
				if ((unsigned char)*fmt++ == '%'
				    && *fmt == ']')
					break;
			}
			if (*fmt)
				fmt++;                /* skip ']'                  */
			argp = sel_argp;
			break;
		case 'g':                             /* 0x44c0 random-access arg   */
			argp = (char *)args + (long)width * 2;
			break;

		/* ---- repeat-emit arms (0x4588 / default @ 0x45a2) ------------- */
		case 'z':                             /* emit NUL `operand` times  */
			c = 0;
			goto repeat_emit;
		case 0:                               /* 0x458c trailing '%'       */
			fmt--;                        /* re-point at the NUL       */
			c = '%';
			goto repeat_emit;
		default:                              /* unknown char: repeat it   */
		repeat_emit: {
			short n = operand;
			while (n-- > 0)
				emit(c);
			break;
		}
		}
		/* value/group/repeat arms land here -> next template char (L45c0) */
	}
}

/* JT[400] public entry — the variadic face the Mac call sites use. Reads one
 * handler fn per char of `hchars` off the vararg list (handler #idx <-> char
 * #idx), then runs the VM. `hchars`/`...` are NULL/absent for plain templates
 * (the standard %d/%s/... conversions need no custom handlers). */
static void jt400(char *fmt, void *args, void (*emit)(short),
                  const char *hchars, ...) __attribute__((unused));
static void jt400(char *fmt, void *args, void (*emit)(short),
                  const char *hchars, ...)
{
	jt400_handler hfns[16];
	short         nh = 0;

	PROBE("jt400");
	if (hchars) {
		const char *p = hchars;
		va_list     ap;

		va_start(ap, hchars);
		while (*p++ && nh < (short)(sizeof hfns / sizeof hfns[0]))
			hfns[nh++] = va_arg(ap, jt400_handler);
		va_end(ap);
	}
	jt400_run(fmt, args, emit, hchars, hfns, nh);
}

/* JT[401] (CODE 3 + 0x3d4c) — read from an open file. Mac builds a
 * PBRead param block + JT[1043]; the port routes to the compat
 * FSRead. Returns bytes read (partial reads on eofErr are kept),
 * or -1 on a hard error. */
static short jt401(short refNum, void *buffer, short count)
                                                __attribute__((unused));
static short jt401(short refNum, void *buffer, short count)
{
	long  n = (long)(unsigned short)count;
	OSErr err;

	PROBE("jt401");
	if (buffer == NULL)
		return -1;
	err = FSRead(refNum, &n, buffer);
	if (err != noErr && err != (OSErr)-39)     /* -39 = eofErr (partial ok) */
		return -1;
	return (short)n;
}

/* JT[410] (CODE 3 + 0x384a, 22 sites) — write to an open file, the
 * PBWrite sibling of jt401's PBRead. The Mac builds a param block and
 * issues JT[1044] (CODE 5+0x5716 = the _Write trap glue, 0xa003 / async
 * 0xa403); the port shims the File Manager layer straight to the compat
 * FSWrite, exactly as jt401/jt412/jt403 already do. Returns bytes
 * written (ioActCount), or -1 on a hard error.
 *
 * NB: boot.c's `jt1044` symbol is an unrelated Window-Manager stub — a
 * stale mis-identification of this JT entry. The faithful File path is
 * the GEMDOS shim here, not that stub. */
static short jt410(short refNum, void *buffer, short count)
                                                __attribute__((unused));
static short jt410(short refNum, void *buffer, short count)
{
	long  n = (long)(unsigned short)count;
	OSErr err;

	PROBE("jt410");
	if (buffer == NULL)
		return -1;
	err = FSWrite(refNum, &n, buffer);
	if (err != noErr)
		return -1;
	return (short)n;
}

/* JT[127] (CODE 6 + 0x0146) — load a design data file, with
 * shared-library fallback.
 *
 *   JT[394](path, "%s%03d.dat", prefix, num);     // "GEO040.dat"
 *   designpath = "";
 *   JT[431](designpath, g_a5_-31336);             // current design name
 *   JT[431](designpath, path);                     // "<design>:GEO040.dat"
 *   refnum = JT[398](designpath, 0);               // open per-design file
 *   if (refnum >= 0) {
 *       *out = JT[401](refnum, buffer, 32766);     // read
 *       JT[411](refnum);                            // close
 *       return;                                     // success
 *   }
 *   // else fall back to the shared "<prefix>.glb" library, pulling
 *   // item `num` through the file cache (JT[987]/JT[467]/JT[468]).
 *
 * The per-design open uses the <design>:<file> HFS path; the compat
 * FSOpen strips it to the bare filename, which resolves in the flat
 * staged gamedata folder. A design overrides individual maps /
 * sprites by shipping its own GEOnnn.DAT etc.; an absent per-design
 * file falls through to the shared GLIB library.
 *
 * Signature: (prefix, num, *out, buffer). *out receives the byte
 * count read; the engine's load routines read it back.
 *
 * The .glb fallback is DEFERRED — it needs the FC group-load path
 * (JT[987] group register + JT[467] fc_read + JT[468] cached handle
 * + GLIB item extract). Until then a non-overridden file reads
 * nothing (the TUTORIAL.DSN tutorial ships GEO040.DAT, GAME001.DAT,
 * STRG003.DAT, so its core files take the per-design path). */
static void jt127(const char *prefix, short num, short *out, void *buffer)
                                                __attribute__((unused));
static void jt127(const char *prefix, short num, short *out, void *buffer)
{
	char  path[402];
	char  dpath[202];
	short refnum;
	short n;

	PROBE("jt127");

	jt394(path, "%s%03d.dat", prefix, (int)(unsigned char)num);
	dpath[0] = 0;
	jt431(dpath, &g_a5_31336);     /* prepend the current design name */
	jt431(dpath, path);            /* "<design>:<prefix><num>.dat"     */

	refnum = jt398(dpath, 0);
	if (refnum >= 0) {
		n = jt401(refnum, buffer, (short)32766);
		if (out != NULL)
			*out = n;
		jt411(refnum);
		return;
	}

	/* .glb shared-library fallback — deferred (see header). */
	PROBE("jt127:glb-fallback-deferred");
	if (out != NULL)
		*out = 0;
}

