/* C-string -> Pascal, for the File Manager Create/FSOpen save-slot calls. */
static void str_c2p(unsigned char *p, const char *s)
{
	short i = 0;

	while (s[i] != 0 && i < 255) {
		p[i + 1] = (unsigned char)s[i];
		i++;
	}
	p[0] = (unsigned char)i;
}

