/* L00e0 (CODE 15 + 0x00e0) — open the slot file for WRITE and run the
 * serializer (jt580) over it. The faithful Mac path threads the FC group
 * cache (JT[988] -> l17e2, built for the read-only GLIB art libraries); a
 * sequential save file doesn't need it, so the port opens the file directly
 * through the File Manager shim and invokes the callback with the live
 * refNum. The design/"SAVE" HFS prefix collapses to the flat staged folder
 * (the FSOpen shim strips paths), so the bare slot name is used. The old
 * file is deleted first so the slot is rewritten, not appended. */
static signed char l00e0(const char *fn, void *cb)
{
	unsigned char pstr[64];
	short         ref;
	short       (*serialize)(short) = (short (*)(short))cb;

	PROBE("L00e0");
	if (fn == NULL || cb == NULL)
		return 0;
	str_c2p(pstr, fn);
	(void)FSDelete((ConstStr255Param)pstr, 0);
	(void)Create((ConstStr255Param)pstr, 0, 'FRUA', 'SAVE');
	if (FSOpen((ConstStr255Param)pstr, 0, &ref) != noErr)
		return 0;
	serialize(ref);
	(void)FSClose(ref);
	return 1;
}

/* L0ce0 (CODE 15 + 0xce0) — byte-swap the multi-byte fields of a character
 * record between native and the little-endian .cch file layout: the word at 82,
 * the three words at 76/78/80, the two longs at 68/72 (jt1199), and the words
 * at 84/86. Involutive (the swaps are their own inverse), so jt578 calls it
 * before and after the 398-byte record write. */
static void l0ce0_c15(unsigned char *rec)
{
	short i;

	PROBE("L0ce0");
	*(short *)(rec + 82) = jt1180(*(short *)(rec + 82));
	for (i = 0; i <= 2; i++)
		*(short *)(rec + i * 2 + 76) =
		    jt1180(*(short *)(rec + i * 2 + 76));
	*(long *)(rec + 68) = jt1199(*(long *)(rec + 68));
	*(long *)(rec + 72) = jt1199(*(long *)(rec + 72));
	*(short *)(rec + 84) = jt1180(*(short *)(rec + 84));
	*(short *)(rec + 86) = jt1180(*(short *)(rec + 86));
}

/* JT[578] (CODE 15 + 0x934) — serialize the current character record (set in
 * g_a5_-6902) to the open file `refNum`. Writes the 398-byte record, then each
 * inventory item (18 bytes from +40, the words at +44/+46 swapped to little-
 * endian), then for a container item (type byte +40 == 'I'/73) its rec[53]
 * sub-items (chained at +58), and finally the spell list (10 bytes/node, word
 * at +2 swapped). Stops on the first short write. Returns 1 on success, 0 on
 * error. The l00e0 file-open callback. */
static short jt578(short refNum)
{
	unsigned char *rec = (unsigned char *)(uintptr_t)g_a5_long(-6902);
	unsigned char *item, *sub, *node;
	signed char    err;
	short          n;

	PROBE("jt578");
	if (rec == NULL)
		return 0;

	l0ce0_c15(rec);                          /* native -> little-endian */
	err = (signed char)(jt410(refNum, rec, 398) != 398 ? 1 : 0);
	l0ce0_c15(rec);                          /* little-endian -> native */

	/* inventory list: rec[8] = head, each node's +0 = next */
	item = (unsigned char *)(uintptr_t)*(long *)(rec + 8);
	while (item != NULL && err == 0) {
		*(short *)(item + 44) = jt1180(*(short *)(item + 44));
		*(short *)(item + 46) = jt1180(*(short *)(item + 46));
		err = (signed char)(jt410(refNum, item + 40, 18) != 18 ? 1 : 0);
		*(short *)(item + 44) = jt1180(*(short *)(item + 44));
		*(short *)(item + 46) = jt1180(*(short *)(item + 46));

		if (err == 0 && item[40] == 73) {  /* container: walk +58 chain */
			sub = item;
			for (n = 1; n <= item[53]; n++) {
				if (err != 0)
					continue;
				sub = (unsigned char *)(uintptr_t)
				      *(long *)(sub + 58);
				*(short *)(sub + 44) =
				    jt1180(*(short *)(sub + 44));
				*(short *)(sub + 46) =
				    jt1180(*(short *)(sub + 46));
				err = (signed char)(jt410(refNum, sub + 40, 18)
				                    != 18 ? 1 : 0);
				*(short *)(sub + 44) =
				    jt1180(*(short *)(sub + 44));
				*(short *)(sub + 46) =
				    jt1180(*(short *)(sub + 46));
			}
		}
		item = (unsigned char *)(uintptr_t)*(long *)item;
	}

	/* spell list: rec[4] = head, each node's +6 = next */
	node = (unsigned char *)(uintptr_t)*(long *)(rec + 4);
	while (node != NULL && err == 0) {
		*(short *)(node + 2) = jt1180(*(short *)(node + 2));
		err = (signed char)(jt410(refNum, node, 10) != 10 ? 1 : 0);
		*(short *)(node + 2) = jt1180(*(short *)(node + 2));
		node = (unsigned char *)(uintptr_t)*(long *)(node + 6);
	}

	return (short)(err == 0 ? 1 : 0);
}

/* JT[903] (CODE 19 + 0x3540) — total container-slot count across the party:
 * sum item[53] over every container (type byte +40 == 'I'/73) in every party
 * member's inventory list (g_a5_-27928 head, +0 = next member, +8 = inventory
 * head, +0 = next item). jt577's load-capacity check keys on it. */
static short jt903(void)
{
	unsigned char *member = (unsigned char *)(uintptr_t)g_a5_long(-27928);
	short          count = 0;

	PROBE("jt903");
	while (member != NULL) {
		unsigned char *item =
		    (unsigned char *)(uintptr_t)*(long *)(member + 8);
		while (item != NULL) {
			if (item[40] == 73)
				count = (short)(count + item[53]);
			item = (unsigned char *)(uintptr_t)*(long *)item;
		}
		member = (unsigned char *)(uintptr_t)*(long *)member;
	}
	return count;
}

/* JT[577] (CODE 15 + 0x3fe) — deserialize a character record (read mirror of
 * jt578) from the open file `refNum` into g_a5_-6902. Reads the 398-byte record
 * (then L0ce0 swaps it native), then rebuilds the inventory list: for each of
 * rec[193] items it reserves a 62-byte node from the -21508 pool (jt477), reads
 * 18 bytes into +40 (words +44/+46 swapped), and for a container (type +40 ==
 * 'I'/73) its rec[53] sub-items chained at +58 — UNLESS adding them would push
 * the party past 120 slots (jt903 + this container + the running count), in
 * which case the sub-items are read-and-discarded, the container node freed
 * (jt471), and the "SCROLLS DROPPED!" notice armed. Finally the spell list
 * (rec[4] head, 10 bytes/node, +2 swapped, on-disk +6 != 0 = "more"). On a read
 * error the partial lists are freed. Returns 1 on success, 0 on error.
 *
 * NOTE: untested breadth lift — reachable once the load path (the CODE 15
 * read-opener + a "Load/Add Character" caller) is wired; needs a Hatari .cch
 * round-trip against jt578 to verify. The error-cleanup container bound reads
 * the Mac's -22216 scratch global; guarded against a NULL port value. */
static void  jt101(const char *fmt, short a, short b);
static short jt577(short refNum) __attribute__((unused));
static short jt577(short refNum)
{
	unsigned char *const inv_pool   = (unsigned char *)&g_a5_byte(-21508);
	unsigned char *const spell_pool = (unsigned char *)&g_a5_byte(-21152);
	unsigned char *rec = (unsigned char *)(uintptr_t)g_a5_long(-6902);
	unsigned char *item, *sub, *prev, *node;
	unsigned char  cont18[18];
	signed char    err;
	unsigned char  overflow = 0, capacc = 0;
	short          remaining, n;
	long           cont_more;

	PROBE("jt577");
	if (rec == NULL)
		return 0;

	err = (signed char)(jt401(refNum, rec, 398) != 398 ? 1 : 0);
	if (err)
		return 0;

	/* take over the (old) inventory + clear the head, then swap the record */
	{
		long old_inv = *(long *)(rec + 8);
		*(long *)(rec + 8) = 0;
		l0ce0_c15(rec);
		remaining = (short)rec[193];           /* item count */
		item = NULL;
		prev = NULL;

		/* inventory read loop (L0464) */
		while (old_inv != 0 && err == 0) {
			if (*(long *)(rec + 8) != 0) {
				jt477(inv_pool, 62, (void *)item);   /* link after */
				prev = item;
				item = (unsigned char *)(uintptr_t)*(long *)item;
			} else {
				jt477(inv_pool, 62, (void *)(rec + 8));
				item = (unsigned char *)(uintptr_t)*(long *)(rec + 8);
				prev = NULL;
			}
			jt399(item, 62, 0);
			err = (signed char)(jt401(refNum, item + 40, 18) != 18 ? 1 : 0);
			remaining--;
			old_inv = (remaining > 0) ? (long)(uintptr_t)item : 0;
			*(short *)(item + 44) = jt1180(*(short *)(item + 44));
			*(short *)(item + 46) = jt1180(*(short *)(item + 46));
			*(long *)item = 0;
			*(long *)(item + 58) = 0;

			if (item[40] != 73)                 /* not a container */
				continue;

			if (jt903() + item[53] + capacc > 120) {
				/* over capacity: read+discard the sub-items, drop the
				 * container node (L0574). */
				overflow = 1;
				for (n = 1; n <= item[53]; n++) {
					if (err == 0)
						err = (signed char)
						    (jt401(refNum, cont18, 18)
						     != 18 ? 1 : 0);
				}
				if (prev != NULL) {
					jt471(*(long *)prev, 62, inv_pool);
					*(long *)prev = 0;
				} else {
					jt471(*(long *)(rec + 8), 62, inv_pool);
					*(long *)(rec + 8) = 0;
				}
				item = prev;
				continue;
			}

			/* within capacity: read the sub-items (L060e) */
			sub = item;
			for (n = 1; n <= item[53]; n++) {
				if (err != 0)
					continue;
				jt477(inv_pool, 62, (void *)(sub + 58));
				sub = (unsigned char *)(uintptr_t)*(long *)(sub + 58);
				jt399(sub, 62, 0);
				err = (signed char)(jt401(refNum, sub + 40, 18)
				                    != 18 ? 1 : 0);
				*(long *)sub = 0;
				*(long *)(sub + 58) = 0;
				if (err != 0)
					item[53] = (unsigned char)(n - 1); /* truncate */
				else
					capacc++;
			}
		}
	}

	/* on error, free the partially-read inventory (L06d0) */
	if (err != 0) {
		item = (unsigned char *)(uintptr_t)*(long *)(rec + 8);
		while (item != NULL) {
			unsigned char *nx = (unsigned char *)(uintptr_t)*(long *)item;
			if (item[40] == 73) {
				unsigned char *scr =
				    (unsigned char *)(uintptr_t)g_a5_long(-22216);
				short bound = (scr != NULL) ? (short)scr[53] : 0;
				sub = (unsigned char *)(uintptr_t)*(long *)(item + 58);
				for (n = 1; sub != NULL && n <= bound; n++) {
					unsigned char *snx = (unsigned char *)
					    (uintptr_t)*(long *)(sub + 58);
					jt471((long)(uintptr_t)sub, 62, inv_pool);
					sub = snx;
				}
			}
			jt471((long)(uintptr_t)item, 62, inv_pool);
			item = nx;
		}
		*(long *)(rec + 8) = 0;
	}

	/* spell list (L0774) */
	if (err == 0) {
		cont_more = *(long *)(rec + 4);          /* old spell head */
		*(long *)(rec + 4) = 0;
		node = NULL;
		while (cont_more != 0 && err == 0) {
			if (*(long *)(rec + 4) != 0) {
				jt477(spell_pool, 10, (void *)(node + 6));
				node = (unsigned char *)(uintptr_t)*(long *)(node + 6);
			} else {
				jt477(spell_pool, 10, (void *)(rec + 4));
				node = (unsigned char *)(uintptr_t)*(long *)(rec + 4);
			}
			err = (signed char)(jt401(refNum, node, 10) != 10 ? 1 : 0);
			cont_more = *(long *)(node + 6);     /* on-disk "more" */
			*(long *)(node + 6) = 0;
			*(short *)(node + 2) = jt1180(*(short *)(node + 2));
		}
		/* on error, free the partial spell list (L083c) */
		if (err != 0) {
			node = (unsigned char *)(uintptr_t)*(long *)(rec + 4);
			while (node != NULL) {
				unsigned char *nx =
				    (unsigned char *)(uintptr_t)*(long *)(node + 6);
				jt471((long)(uintptr_t)node, 10, spell_pool);
				node = nx;
			}
			*(long *)(rec + 4) = 0;
		}
	}

	*(long *)(rec + 64) = 0;
	*(long *)rec = 0;
	if (err == 0 && overflow)
		jt101(ua_strs_at(0x4c82) /* "SCROLLS DROPPED!" */, 11, 0);

	return (short)(err == 0 ? 1 : 0);
}

/* JT[584] (CODE 15 + 0xb5a) — save a character record to its .cch file. Builds
 * the basename from `suffix` (or the character name rec[96] when suffix is
 * empty) + the "cch" extension, then — for an auto-named character — builds the
 * SAVE-folder path, checks for an existing file (jt988), and on a collision
 * offers "Update %s?" (jt159) or prompts for a new name (jt98). Finally stamps
 * the record into g_a5_-6902 and runs the serializer jt578 through the file
 * opener l00e0. */
static short l17e2(short kind, const char *name, short mode, void *cbp);
static void jt584(long rec_l, const char *suffix)
{
	unsigned char *rec = (unsigned char *)(uintptr_t)rec_l;
	const char    *ext = ua_strs_at(0x4c94);   /* "cch" */
	char           fname[64];
	char           path[260];
	char           prompt[80];
	unsigned char  named;

	PROBE("jt584");
	if (suffix == NULL || suffix[0] == 0) {    /* auto-name from rec[96] */
		jt384(fname, (char *)(rec + 96));
		jt130(fname);
		jt419(fname, ext, 1);
		named = 0;
	} else {
		jt384(fname, suffix);
		jt419(fname, ext, 1);
		named = 1;
	}

	if (l005a() == 0)                          /* save-folder precondition */
		return;
	goto check_named;

 build_path:
	path[0] = 0;
	jt431(path, (char *)&g_a5_byte(-31336));   /* design dir */
	jt431(path, ua_strs_at(0x4c98));           /* "SAVE" */
	jt431(path, fname);
	if (l17e2(0, path, 0, NULL) == 0)          /* jt988: file doesn't exist */
		goto do_save;
	jt76();
	jt384(prompt, jt488(ua_strs_at(0x4c9e) /* "Update %s?" */,
	                    (char *)(rec + 96)));
	named = (unsigned char)jt159(prompt, 0);
	if (named != 0)
		goto check_named;
	jt176();
	for (;;) {                                 /* prompt a new file name */
		char *nm = jt98((long)(uintptr_t)ua_strs_at(0x4caa)
		                /* "New file name:" */, 0, 0, 15);
		jt384(fname, nm);
		jt130(fname);
		if (fname[0] == 0 && jt91())
			continue;
		break;
	}
	if (jt91() == 0)                           /* cancelled */
		return;
	jt419(fname, ext, 1);

 check_named:
	if (named == 0)
		goto build_path;

 do_save:
	g_a5_long(-6902) = (long)(uintptr_t)rec;
	l00e0(fname, (void *)jt578);
}

/* l_cch_read — the read counterpart of l00e0: open `fn` (the flat gamedata
 * basename, same location l00e0 writes), point g_a5_-6902 at `rec`, and run the
 * jt577 deserializer over the open file. Returns 1 on success. This is the
 * read-opener that makes jt577 reachable; the faithful CODE 15 L0006 opener
 * builds nested SAVE paths through jt987/l16c6, which would not agree with
 * l00e0's flat-shim write location for a round-trip, so the port mirrors l00e0
 * instead (ADR-0003). */
static signed char l_cch_read(const char *fn, unsigned char *rec)
    __attribute__((unused));
static signed char l_cch_read(const char *fn, unsigned char *rec)
{
	unsigned char pstr[64];
	short         ref;

	PROBE("l_cch_read");
	if (fn == NULL || rec == NULL)
		return 0;
	str_c2p(pstr, fn);
	if (FSOpen((ConstStr255Param)pstr, 0, &ref) != noErr)
		return 0;
	g_a5_long(-6902) = (long)(uintptr_t)rec;
	jt577(ref);
	(void)FSClose(ref);
	return 1;
}

/* ====================================================================
 * jt21 derived-stat math primitives (CODE 6). These pure-logic helpers
 * compute the AD&D Strength index, weight allowance, encumbrance-driven
 * movement, and the AC / save contributions of equipped items; jt21
 * (the character-record recompute) wires them together. The item-type
 * table base is g_a5_27944 (16-byte records: [0]=kind, [6]=codec byte).
 * ==================================================================== */

/* L1d54 (CODE 6 + 0x1d54) — map a character's Strength (player[113], plus the
 * exceptional-strength percentile player[124] when STR is 18) to the dense
 * 0..30 index the weight/encumbrance tables key on. 18/01-50 -> 19, /51-75 ->
 * 20, /76-90 -> 21, /91-99 -> 22, /00 -> 23; STR 19..25 (giant) -> STR+5. */
static short l1d54(const unsigned char *m) __attribute__((unused));
static short l1d54(const unsigned char *m)
{
	short s = m[113];

	PROBE("L1d54");
	if (s <= 17)                    /* L1d78 — ordinary STR 0..17 */
		return m[113];
	if (s == 18) {                  /* L1d86 — exceptional STR */
		short pct = m[124];
		if (pct == 0)   return 18;
		if (pct <= 50)  return 19;
		if (pct <= 75)  return 20;
		if (pct <= 90)  return 21;
		if (pct <= 99)  return 22;
		return 23;              /* pct == 100 */
	}
	if (s >= 19 && s <= 25)         /* L1e28 — giant Strength */
		return (short)(m[113] + 5);
	return 0;
}

/* L2000 (CODE 6 + 0x2000) — the AD&D weight-allowance adjustment (tenths of a
 * pound) for a character's Strength index (via L1d54): negative for weak STR,
 * climbing steeply for 18/xx and giant grades. */
static short l2000(const unsigned char *m) __attribute__((unused));
static short l2000(const unsigned char *m)
{
	short s = l1d54(m);

	PROBE("L2000");
	if (s <= 0)   return 0;         /* (asm leaves it unset; 0 is safe) */
	if (s <= 3)   return -350;
	if (s <= 5)   return -250;
	if (s <= 7)   return -150;
	if (s <= 11)  return 0;
	if (s <= 13)  return 100;
	if (s <= 15)  return 200;
	if (s <= 16)  return 350;
	if (s <= 21)  return (short)((s - 17) * 250 + 500);
	if (s <= 26)  return (short)((s - 22) * 1000 + 2000);
	if (s <= 27)  return 7500;
	if (s <= 30)  return (short)((s - 28) * 3000 + 9000);
	return 0;
}

/* L0d44 (CODE 6 + 0x0d44) — clamp a character's movement rate (player[396]) by
 * encumbrance: the remaining allowance is the carry capacity (player[86]) less
 * the Strength weight allowance (L2000), bucketed >768 -> 6, >512 -> 9, else
 * keep current; only ever lowers the rate. */
static void l0d44(unsigned char *m) __attribute__((unused));
static void l0d44(unsigned char *m)
{
	short rem = (short)(*(short *)(m + 86) - l2000(m));
	short mc;

	PROBE("L0d44");
	if (rem < 0)
		rem = 0;
	if (rem > 1024)         mc = 3;
	else if (rem <= 512)    mc = m[396];
	else if (rem <= 768)    mc = 9;
	else                    mc = 6;
	if ((unsigned char)mc < m[396])
		m[396] = (unsigned char)mc;
}

/* L1ba4 (CODE 6 + 0x1ba4) — the to-hit / damage style adjustment keyed on
 * player[119] (a low attribute score): 1-3 -> -4, 4-6 -> -3..-1, 15-18 ->
 * +1..+4, 19-20 -> +4, 21-23 -> +5, 24-25 -> +6, else 0. */
static short l1ba4(const unsigned char *m) __attribute__((unused));
static short l1ba4(const unsigned char *m)
{
	short v = m[119];

	PROBE("L1ba4");
	if (v >= 1 && v <= 3)    return -4;
	if (v >= 4 && v <= 6)    return (short)(v - 7);
	if (v >= 15 && v <= 18)  return (short)(v - 14);
	if (v >= 19 && v <= 20)  return 4;
	if (v >= 21 && v <= 23)  return 5;
	if (v >= 24 && v <= 25)  return 6;
	return 0;
}

/* L0b3e (CODE 6 + 0x0b3e) — set movement rate (player[396]) from an item whose
 * type record (g_a5_27944 + item[40]*16) is kind 2 (a mount/vehicle): by the
 * item's speed field item[44] (>399 -> 6, <=150 -> base player[136], else 9),
 * +3 when item[48] is set and the rate is still <=9. */
static void l0b3e(unsigned char *m, const unsigned char *item) __attribute__((unused));
static void l0b3e(unsigned char *m, const unsigned char *item)
{
	const unsigned char *rec =
		(const unsigned char *)(uintptr_t)g_a5_long(-27944)
		+ ((unsigned)item[40] << 4);
	unsigned short w;

	PROBE("L0b3e");
	if (rec[0] != 2)
		return;
	w = *(unsigned short *)(item + 44);
	if (w > 399)            m[396] = 6;
	else if (w <= 150)      m[396] = m[136];
	else                    m[396] = 9;
	if (item[48] != 0 && m[396] <= 9)
		m[396] = (unsigned char)(m[396] + 3);
}

/* L0be0 (CODE 6 + 0x0be0) — fold one equipped item's contributions into the
 * AC / save accumulator `acc` (6 bytes) and the carried-weight field
 * player[195]. The item type record's codec byte (rec[6]) gates the item
 * (bit7 must be set) and carries a magnitude in its low 7 bits; rec[0] (kind)
 * selects which slot the item's [48] bonus lands in:
 *   kind 1            -> acc[1] = mag + bonus
 *   mag != 0          -> acc[5] = max(acc[5], mag + bonus); flag a worn shield
 *                        (flagout) when bonus>0 and kind==2
 *   mag == 0, kind 9  -> acc[3] = max(acc[3], bonus)
 *   mag == 0, kind 7  -> acc[4] = bonus
 *   mag == 0, else    -> acc[2] += bonus, and player[195] += item[49] */
static void l0be0(unsigned char *m, const unsigned char *item,
                  unsigned char *acc, unsigned char *flagout) __attribute__((unused));
static void l0be0(unsigned char *m, const unsigned char *item,
                  unsigned char *acc, unsigned char *flagout)
{
	const unsigned char *rec =
		(const unsigned char *)(uintptr_t)g_a5_long(-27944)
		+ ((unsigned)item[40] << 4);
	short mag  = rec[6];
	short kind;
	short bonus = (signed char)item[48];

	PROBE("L0be0");
	if ((mag & 0x80) == 0)                  /* codec bit 7 must be set */
		return;
	mag &= 0x7f;
	kind = rec[0];

	if (kind == 1) {                        /* L0b88-ish: direct slot */
		acc[1] = (unsigned char)(mag + bonus);
		return;
	}
	if (mag != 0) {                         /* L0cec — best-of magnitude */
		short v = (short)(bonus + mag);
		if ((unsigned short)v <= (unsigned short)(signed char)acc[5])
			return;
		acc[5] = (unsigned char)v;
		if (bonus > 0 && kind == 2)
			flagout[0] = 1;
		return;
	}
	/* mag == 0 (L0c60) */
	if (kind == 9) {                        /* AC: keep the best */
		if (bonus > (signed char)acc[3])
			acc[3] = (unsigned char)bonus;
	} else if (kind == 7) {
		acc[4] = (unsigned char)bonus;
	} else {
		acc[2] = (unsigned char)((signed char)acc[2] + bonus);
	}
	m[195] = (unsigned char)((signed char)m[195] + (signed char)item[49]);
}

/* L2fd8 (CODE 6 + 0x2fd8) — the higher of a class field player[idx+157] and,
 * when L2f4c says the class has the alternate progression, player[idx+164]. */
static short l2fd8(const unsigned char *m, short idx) __attribute__((unused));
static short l2fd8(const unsigned char *m, short idx)
{
	short i = (short)(signed char)(idx & 0xff);
	unsigned char a = (m + i)[157];
	unsigned char b = l2f4c(m) ? (m + i)[164] : 0;

	PROBE("L2fd8");
	return (a > b) ? (short)a : (short)b;
}

/* L1e58 (CODE 6 + 0x1e58) — the AD&D Strength "to-hit" adjustment, keyed on
 * the Strength index (L1d54): -3 at STR 1-3 ... +1 at 17-19, climbing to +7
 * at giant STR 30. */
static short l1e58(const unsigned char *m) __attribute__((unused));
static short l1e58(const unsigned char *m)
{
	short s = l1d54(m);

	PROBE("L1e58");
	if (s <= 0)   return 0;
	if (s <= 3)   return -3;
	if (s <= 5)   return -2;
	if (s <= 7)   return -1;
	if (s <= 16)  return 0;
	if (s <= 19)  return 1;
	if (s <= 22)  return 2;
	if (s <= 25)  return 3;
	if (s <= 27)  return 4;
	if (s <= 30)  return (short)(s - 23);
	return 0;
}

/* L1f3e (CODE 6 + 0x1f3e) — the AD&D Strength "damage" adjustment, keyed on
 * the Strength index (L1d54): -2 at STR 1-2 ... +1 at 16-17, climbing to +14
 * at giant STR 30. Named l1f3e_c6: the bare l1f3e is CODE 7's bar sizer (a
 * distinct function at the same segment-local offset). */
static short l1f3e_c6(const unsigned char *m) __attribute__((unused));
static short l1f3e_c6(const unsigned char *m)
{
	short s = l1d54(m);

	PROBE("L1f3e");
	if (s <= 0)   return 0;
	if (s <= 2)   return -2;
	if (s <= 5)   return -1;
	if (s <= 15)  return 0;
	if (s == 16)  return 1;
	if (s <= 19)  return (short)(s - 16);
	if (s <= 29)  return (short)(s - 17);
	if (s == 30)  return 14;
	return 0;
}

/* L1c92 (CODE 6 + 0x1c92) — a second adjustment keyed on player[119] (used by
 * L08f4 as a magic-weapon to-hit term): 0-2 -> -4, 3-5 -> -3..-1, 6-15 -> 0,
 * 16-18 -> +1..+3, 19-20 -> +3, 21-23 -> +4, 24-25 -> +5, else 0. Named
 * l1c92_c6: the bare l1c92 is an unrelated CODE save-helper stub. */
static short l1c92_c6(const unsigned char *m) __attribute__((unused));
static short l1c92_c6(const unsigned char *m)
{
	short v = m[119];

	PROBE("L1c92");
	if (v > 25)   return 0;
	if (v <= 2)   return -4;
	if (v <= 5)   return (short)(v - 6);
	if (v <= 15)  return 0;
	if (v <= 18)  return (short)(v - 15);
	if (v <= 20)  return 3;
	if (v <= 23)  return 4;
	return 5;               /* 24..25 */
}

/* L08f4 (CODE 6 + 0x08f4) — recompute the equipped-weapon combat columns from
 * the weapon in player[12]. Resets to-hit (player[384] <- player[127]) and
 * damage (player[393] <- weapon record[11]), then folds in, gated by the
 * weapon type-record's flag byte (rec[14]):
 *   bit1 -> + L1c92 (a STR/[119] to-hit term)
 *   bit2 -> + L1e58 to-hit and + L1f3e damage (STR adjustments)
 * Adds the weapon's [48] bonus (plus an off-hand item [60] when rec bit7, and
 * ammo [56] when rec bit0) to damage; a proficiency +1 (weapon types 18, 19,
 * 21-27 when player[88]==0) goes to to-hit. Finally stamps the range columns
 * player[389]/[391] from rec[9]/[10]. */
static void l08f4(unsigned char *m) __attribute__((unused));
static void l08f4(unsigned char *m)
{
	unsigned char *item = *(unsigned char **)(m + 12);
	const unsigned char *base =
		(const unsigned char *)(uintptr_t)g_a5_long(-27944);
	unsigned char itype;
	short tmp;

	PROBE("L08f4");
	if (item == NULL)
		return;
	itype = item[40];

	m[384] = m[127];                                /* to-hit base */
	if (base[itype * 16 + 14] & 2)
		m[384] = (unsigned char)(m[384] + l1c92_c6(m));

	m[393] = base[itype * 16 + 11];                 /* damage base */
	if (base[itype * 16 + 14] & 4) {
		m[384] = (unsigned char)(m[384] + l1e58(m));
		m[393] = (unsigned char)((signed char)m[393] + l1f3e_c6(m));
	}

	tmp = (signed char)item[48];                    /* weapon bonus */
	if ((base[itype * 16 + 14] & 0x80) && *(long *)(m + 60) != 0) {
		unsigned char *off = *(unsigned char **)(m + 60);
		tmp = (short)(tmp + (signed char)off[48]);
	}
	if ((base[itype * 16 + 14] & 1) && *(long *)(m + 56) != 0) {
		unsigned char *ammo = *(unsigned char **)(m + 56);
		tmp = (short)(tmp + (signed char)ammo[48]);
	}
	m[393] = (unsigned char)((signed char)m[393] + tmp);    /* damage += bonus */

	if (m[88] == 0) {                               /* proficiency +1 */
		short it = item[40];
		if ((it >= 21 && it <= 27) || it == 19 || it == 18)
			tmp++;
	}
	m[384] = (unsigned char)(m[384] + tmp);         /* to-hit += bonus(+prof) */

	m[389] = base[itype * 16 + 9];
	m[391] = base[itype * 16 + 10];
}

/* L1554 (CODE 6 + 0x1554) — recompute movement (player[396]) and the
 * attacks-per-round count (g_a5_25263). Reset move to the racial base
 * player[136], let each carried mount/vehicle item (item[50] set) override it
 * (L0b3e), clamp by encumbrance (L0d44), then double/halve for the
 * haste/slow/extra conditions (jt41 codes 39/42/74). The attack count starts
 * from the move rate, adds the active-monster bonus g_a5_28006[28] (min 1) for
 * a 0 player[95], is doubled, and is zeroed by condition 178. */
static short l1554(unsigned char *m) __attribute__((unused));
static short l1554(unsigned char *m)
{
	unsigned char *item;
	void *desc = 0;

	PROBE("L1554");
	m[396] = m[136];                                /* base move */
	for (item = *(unsigned char **)(m + 8); item != NULL;
	     item = *(unsigned char **)item) {
		if (item[50] != 0)
			l0b3e(m, item);
	}
	l0d44(m);                                       /* encumbrance clamp */

	if (jt41((long)(uintptr_t)m, 39, &desc))
		m[396] = (unsigned char)(m[396] * 2);
	if (jt41((long)(uintptr_t)m, 42, &desc))
		m[396] = (unsigned char)(m[396] >> 1);
	if (jt41((long)(uintptr_t)m, 74, &desc))
		m[396] = (unsigned char)(m[396] * 2);

	g_a5_byte(-25263) = m[396];

	if (m[95] == 0) {                               /* L1626 */
		const unsigned char *h = (const unsigned char *)g_a5_28006;
		short base = (short)(unsigned char)g_a5_byte(-25263);
		if ((short)((signed char)h[28] + base) < 1)
			g_a5_byte(-25263) = 1;
		else
			g_a5_byte(-25263) =
				(unsigned char)((unsigned char)h[28] + base);
	}
	g_a5_byte(-25263) = (unsigned char)(g_a5_byte(-25263) * 2);
	if (jt41((long)(uintptr_t)m, 178, &desc))
		g_a5_byte(-25263) = 0;

	return (short)(unsigned char)g_a5_byte(-25263);
}

/* JT[21] (CODE 6 + 0x16aa, 26 sites) — recompute every derived field of a
 * character record `mp` from its inventory and ability scores. The spine:
 *   1. Clear the 13 equip-by-kind slots (mp+12..mp+60), reset counters.
 *   2. First inventory pass: tally carried weight (mp[86]), and for each
 *      equipped item (item[50]) file it into the slot for its type-record
 *      kind (rec[0]); kind 9 -> the two ring slots mp+48/mp+52; item type 30
 *      -> ammo (mp+56); types 12/74 -> off-hand (mp+60); accumulate rec[1]
 *      into mp[194].
 *   3. Add the three base-weight words mp[76/78/80] into the capacity mp[86].
 *   4. Copy the base combat columns mp[173..178] into mp[389..394].
 *   5. Reset to-hit/damage/move/save to their bases; seed the adjustment
 *      buffer adj[0] with the L1ba4 ability bonus; for an unarmed char add the
 *      Strength to-hit/damage (L1e58/L1f3e); recompute the weapon columns
 *      (L08f4).
 *   6. Second pass: apply each equipped item's movement (L0b3e) and fold its
 *      AC/save bonuses into adj[] (L0be0); cap the shield/cloak terms.
 *   7. Recompute attacks/movement (L1554), fold adj[] into the save stat
 *      mp[385], set AC mp[386] = adj sums - 2, and (unless class 6) walk the
 *      save category mp[148] through L2fd8/jt397 for the 2/4/3 columns. */
static void jt21(long mp) __attribute__((unused));
static void jt21(long mp)
{
	unsigned char *m = (unsigned char *)(uintptr_t)mp;
	const unsigned char *base =
		(const unsigned char *)(uintptr_t)g_a5_long(-27944);
	unsigned char *item;
	unsigned char  adj[6];          /* fp@(-14..-9): ability + item bonuses */
	unsigned char  flag = 0;        /* fp@(-7) */
	short i, n;

	PROBE("jt21");

	for (i = 0; i <= 12; i++)               /* clear equip-by-kind slots */
		*(long *)(m + 12 + i * 4) = 0;
	m[193] = 0;
	m[194] = 0;
	*(short *)(m + 86) = 0;
	g_a5_word(-31232) = 0;

	/* First inventory pass: weight tally + equip-slot filing. */
	for (item = *(unsigned char **)(m + 8); item != NULL;
	     item = *(unsigned char **)item) {
		short w = *(short *)(item + 44);
		unsigned char kind;

		m[193]++;
		if (item[53] != 0)
			w = (short)(item[53] * w);      /* * quantity */
		*(short *)(m + 86) += w;
		if (item[50] == 0)                      /* not equipped */
			continue;

		g_a5_word(-31232) += w;
		kind = base[item[40] * 16 + 0];
		if (kind <= 8) {                        /* JT[3] cases 0..8 */
			*(long *)(m + 12 + kind * 4) = (long)(uintptr_t)item;
		} else if (kind == 9) {                 /* two ring slots */
			if (*(long *)(m + 48) == 0)
				*(long *)(m + 48) = (long)(uintptr_t)item;
			else if (*(long *)(m + 52) == 0)
				*(long *)(m + 52) = (long)(uintptr_t)item;
		}
		if (item[40] == 30)                     /* ammo */
			*(long *)(m + 56) = (long)(uintptr_t)item;
		if (item[40] == 12 || item[40] == 74)   /* off-hand */
			*(long *)(m + 60) = (long)(uintptr_t)item;
		m[194] = (unsigned char)(m[194] + base[item[40] * 16 + 1]);
	}

	for (i = 0; i <= 2; i++)                /* fold base weights into capacity */
		*(short *)(m + 86) += *(short *)(m + 76 + i * 2);

	for (i = 1; i <= 2; i++) {              /* copy base combat columns */
		m[389 + (i - 1)] = m[173 + (i - 1)];
		m[391 + (i - 1)] = m[175 + (i - 1)];
		m[393 + (i - 1)] = m[177 + (i - 1)];
	}

	/* Reset combat/move/save bases + Strength adjustments. */
	l5f4e(adj, 6);
	flag = 0;
	m[195] = 0;
	m[385] = m[179];
	m[396] = m[136];
	m[384] = m[127];
	adj[0] = (unsigned char)l1ba4(m);
	if (*(long *)(m + 12) == 0) {           /* unarmed: STR to-hit/damage */
		m[384] = (unsigned char)(m[384] + l1e58(m));
		m[393] = (unsigned char)((signed char)m[393] + l1f3e_c6(m));
	}
	l08f4(m);                               /* weapon columns */

	/* Second pass: per-item movement + AC/save accumulation into adj[]. */
	for (item = *(unsigned char **)(m + 8); item != NULL;
	     item = *(unsigned char **)item) {
		if (item[50] != 0) {
			l0b3e(m, item);
			l0be0(m, item, adj, &flag);
		}
	}
	if (flag != 0) {                        /* L1a24 — cap shield/cloak terms */
		if ((signed char)adj[3] > 0)
			adj[3] = 0;
		if ((signed char)adj[4] > 0) {
			unsigned char *sh = *(unsigned char **)(m + 40);
			if (sh == NULL || sh[40] != 58)
				adj[4] = 0;
		}
	}

	/* Attacks/movement, then fold adj[] into the save stat + AC + categories. */
	m[396] = (unsigned char)((l1554(m) & 0xff) >> 1);
	if ((unsigned short)(signed char)adj[5] < (unsigned short)m[385])
		adj[5] = m[385];
	m[385] = 0;
	for (n = 0; n <= 5; n++)
		m[385] = (unsigned char)((unsigned char)m[385] + (signed char)adj[n]);
	m[386] = (unsigned char)((signed char)adj[2] + (signed char)adj[5]
	                       + (signed char)adj[4] + (signed char)adj[3] - 2);
	m[148] = 1;
	if (m[88] == 6)                         /* class 6 (monster): no save calc */
		return;
	m[148] = (unsigned char)jt397(m[148], (short)(l2fd8(m, 2) & 0xff));
	m[148] = (unsigned char)jt397(m[148], (short)(l2fd8(m, 4) & 0xff));
	m[148] = (unsigned char)jt397(m[148], (short)(l2fd8(m, 3) & 0xff));
}

