/* JT[888] (CODE 19 + 0x596a) — the interactive target picker ("Cast
 * Spell on whom").  Highlights the current pick (jt153/-13014), then
 * loops: roster repaint (jt937), prompt + keystroke (jt163 over the
 * -13844 bar), and a THINK C JT[1] SPARSE switch on the key — NOT a
 * JT[3] dense table; the inline format is
 *     .short n, default_off, (value, offset)*n
 * (each offset PC-relative to its own slot; jt3_extract mis-decodes
 * these).  Pairs here: ESC(27) -> cancel-key, CR(13)/0x84 -> cycle
 * forward through the -27928 party list (wrap to head), 0x85/0x88 ->
 * cycle backward (predecessor scan; wrap to tail), 0x87 -> keep,
 * default -> clear the pick when `f1` is set.  Loop exits when the
 * jt163 key class is < 2 or == 27.  The chosen record lands back in
 * *target.  -22226/-22268 are saved/restored around the loop;
 * -24148/-24146 stage the active combatant for the backward arm
 * (read when -22225 is set). */
static void jt888(long str_l, short f1, short f2, long *target)
                                                 __attribute__((unused));
static void jt888(long str_l, short f1, short f2, long *target)
{
	unsigned char *str = (unsigned char *)(uintptr_t)str_l;
	unsigned char buf[52];
	unsigned char saved26, saved68, key, ctr;
	long cur;

	PROBE("jt888");
	jt153(*target);
	saved26 = g_a5_byte(-22226);
	g_a5_byte(-24148) = (unsigned char)f2;
	g_a5_long(-24146) = g_a5_long(-27932);
	key = 255;
	saved68 = g_a5_byte(-22268);
	g_a5_byte(-22268) = 0;

	while (!(key < 2 || key == 27)) {
		jt937(*target);
		ctr = (g_a5_byte(-27990) == 2 ||
		       g_a5_byte(-27990) == 6) ? 1 : 0;
		if (g_a5_byte(-27990) == 0)
			g_a5_byte(-22226) = 1;     /* dead store (faithful) */
		g_a5_byte(-22226) = saved26;
		cur = *target;
		jt153(*target);
		jt179((short)(((unsigned char)f1 != 0) ? 1 : 0));
		if (str[0] != 0)
			jt384((char *)buf,
			      jt488(ua_strs_at(0x5e4e) /* "%s%s" */,
			            (const char *)str,
			            ua_strs_at(0x5e54) /* " " */));
		else
			jt384((char *)buf,
			      jt488(ua_strs_at(0x5e56) /* "%s" */,
			            (const char *)str));
		key = (unsigned char)jt163(buf, g_a5_long(-13844),
		                           (short)1, (short)ctr);
		cur = jt162();
		if (g_a5_byte(-24139) != 0) {
			switch (key) {          /* JT[1] sparse table @0x5a94 */
			case 27:                /* ESC -> cancel-key */
				key = 0;
				break;
			case 13:                /* CR / 0x84 -> next member */
			case 0x84:
				cur = *(long *)(uintptr_t)cur;
				if (cur == 0)
					cur = g_a5_long(-27928);
				break;
			case 0x85:              /* 0x85 / 0x88 -> previous */
			case 0x88:
				if (g_a5_byte(-22225) != 0) {
					cur = (g_a5_byte(-24148) != 0)
					    ? g_a5_long(-24146)
					    : g_a5_long(-27932);
				} else {
					cur = g_a5_long(-27928);
					if (*target == g_a5_long(-27928)) {
						/* wrap to the tail */
						while (*(long *)(uintptr_t)cur != 0)
							cur = *(long *)(uintptr_t)cur;
					} else {
						/* predecessor scan */
						while (*(long *)(uintptr_t)cur != *target)
							cur = *(long *)(uintptr_t)cur;
					}
				}
				break;
			case 0x87:              /* keep the pick */
				break;
			default:                /* anything else */
				if ((unsigned char)f1 != 0)
					cur = 0;
				break;
			}
		} else {
			if ((unsigned char)f1 != 0 && key == 1)
				cur = 0;
		}
		*target = cur;
		jt153(*target);
	}

	g_a5_byte(-22268) = saved68;
	g_a5_byte(-24148) = 0;
}

/* The -24070 targeting callback ABI (the breath/gaze jt7xx handlers and
 * jt842/jt851 call through g_a5_long(-24070) with these args).  Two
 * implementations exist: jt601 (out of combat, below) and jt538
 * (CODE 14+0x2028, in combat — also below).  Registration sites: CODE 13
 * L0006 (combat teardown, +0x010e) and jt610 (CODE 16 handler-table
 * init) install jt601; jt511 (CODE 13+0x5a6) installs jt538. */
typedef void (*ua_target_cb)(short code, short cnt, unsigned char *out);

/* JT[601] (CODE 16 + 0x63ae) — the out-of-combat targeting callback.
 * Stages the active combatant (-27932) as the target (-23508, which is
 * slot 1 of the -23512 target table) with count (-23510) 1 and *out=1,
 * then dispatches on byte 7 of the -16906 hazard row for `code`:
 *   1 -> self only (keep the staging);
 *   2 -> interactive pick: play-frame redraw (jt23), seed from the
 *        remembered pick (-27936), run jt888 ("Cast Spell on whom"),
 *        remember the result; a null pick clears count and *out;
 *   3 -> the whole -27928 party list copied into the -23512 slots
 *        (each record's first long is its next pointer), count = size;
 *   default -> *out = 0. */
static void jt601(short code, short cnt, unsigned char *out)
                                                 __attribute__((unused));
static void jt601(short code, short cnt, unsigned char *out)
{
	unsigned char idx = (unsigned char)code;

	PROBE("jt601");
	(void)cnt;
	g_a5_long(-23508) = g_a5_long(-27932);
	g_a5_byte(-23510) = 1;
	*out = 1;
	switch ((short)(signed char)g_a5_buf(-16906)[(long)idx * 16 + 7]) {
	case 1:
		break;
	case 2:
		jt23();
		if (g_a5_long(-27936) != 0)
			g_a5_long(-23508) = g_a5_long(-27936);
		jt888((long)(uintptr_t)ua_strs_at(0x532e)
		      /* "Cast Spell on whom" */,
		      (short)1, (short)1, &g_a5_long(-23508));
		g_a5_long(-27936) = g_a5_long(-23508);
		if (g_a5_long(-23508) == 0) {
			g_a5_byte(-23510) = 0;
			*out = 0;
		}
		break;
	case 3:
		/* slot k lives at A5-23512 + 4k; the count -23510 is 1-based
		 * and slot 1 aliases the -23508 target long */
		g_a5_long(-23512 + (long)g_a5_byte(-23510) * 4) =
			g_a5_long(-27928);
		while (*(long *)(uintptr_t)
		       g_a5_long(-23512 + (long)g_a5_byte(-23510) * 4) != 0) {
			g_a5_long(-23512 + ((long)g_a5_byte(-23510) + 1) * 4) =
			    *(long *)(uintptr_t)
			    g_a5_long(-23512 + (long)g_a5_byte(-23510) * 4);
			g_a5_byte(-23510)++;
		}
		break;
	default:
		*out = 0;
		break;
	}
}

/* The 10-byte pick descriptor jt538/L1efa pass to the pickers (jt539 /
 * L1dd6 / L4dee): the picked record's pointer, then its combat-map cell.
 * The Mac reads the cell as the low BYTES at +5 / +7 (the X/Y words'
 * low halves).  A failed pick zero-fills it via jt399(buf, 10, 0). */
struct ua_pick10 {
	long rec;	/* +0  picked record (entity ptr), 0 = none */
	short x;	/* +4  cell X (low byte at +5 is what's read) */
	short y;	/* +6  cell Y (low byte at +7) */
	short extra;	/* +8 */
};

/* JT[600] (CODE 16 + 0x5f26) — spell range, in combat-map cells, from
 * the -16906 hazard row for `code`: byte2 = base, byte3 = per-level
 * multiplier.  In combat the level term is jt17(code, 0) (caster level,
 * low byte); out of combat (-23230 set) it's a flat 6.  Code 125 is
 * quartered; a zero range becomes 1 when byte6 (the targeting-mode
 * field) is non-zero; 255 also folds to 1. */
static unsigned char jt600(short code)
{
	const unsigned char *info =
	    g_a5_buf(-16906) + (long)(unsigned char)code * 16;
	unsigned char range;

	PROBE("jt600");
	if (g_a5_byte(-23230) == 0) {
		short lvl = jt17((short)(unsigned char)code, (short)0);

		range = (unsigned char)((lvl & 255) * info[3] + info[2]);
	} else {
		range = (unsigned char)(info[3] * 6 + info[2]);
	}
	if ((unsigned char)code == 125)
		range = (unsigned char)(range >> 2);
	if (range == 0 && info[6] != 0)
		range = 1;
	if (range == 255)
		range = 1;
	return range;
}

/* JT[539] (CODE 14 + 0x3b6c) — the in-combat interactive crosshair
 * pick: arms the -24140 pick mode, runs the cursor UI over the combat
 * map out to `range` cells from `actor`, and fills `buf` (rec + cell)
 * with the choice, *res = picked.  PROBE stub pending its own lift:
 * fail the pick the way the real entry starts out (zeroed buf, *res 0)
 * so L1efa degrades to its no-target path. */
static void jt539(long actor_l, short range, short zero, short areaflag,
                  short flag, unsigned char *res, struct ua_pick10 *buf)
{
	PROBE("jt539");
	(void)actor_l;
	(void)range;
	(void)zero;
	(void)areaflag;
	(void)flag;
	jt399(buf, (short)10, (short)0);
	*res = 0;
}

/* CODE 14 + 0x1dd6 (local, ~292 B) — pick the next target from the
 * already-built area list (repeat picks, cnt != 0, no area re-aim).
 * PROBE stub pending its own lift; returns 0 = no pick. */
static unsigned char l1dd6(struct ua_pick10 *buf, short *a, short *b,
                           char *code_p, unsigned char *c)
{
	PROBE("L1dd6");
	(void)buf;
	(void)a;
	(void)b;
	(void)code_p;
	(void)c;
	return 0;
}

/* CODE 14 + 0x4dee (local) — repeat-pick for the area modes that
 * re-aim per target (cnt != 0, areaflag set, byte6 != 8): re-runs the
 * jt508 area scan around the spell's special-case rules (codes 87 / 51
 * / 115 / 47 vs the -28006 flags, like jt538's cases 8-14).  PROBE
 * stub pending its own lift; returns 0 = no pick. */
static unsigned char l4dee(short code, struct ua_pick10 *buf)
{
	PROBE("L4dee");
	(void)code;
	(void)buf;
	return 0;
}

/* CODE 14 + 0x1efa (local) — one target pick for jt538.  First pick
 * (cnt == 0): interactive crosshair via jt539 at jt600(code) range
 * (aim-anywhere flag set unless code 83), and the choice is remembered
 * in the actor's sub-record long +12.  Repeat picks (cnt != 0) come
 * from the built list: L1dd6 when there's no area re-aim (areaflag 0,
 * or targeting mode byte6 == 8), else L4dee.  A hit posts the cell to
 * -23236/-23235 and returns 1; a miss zero-fills the descriptor. */
static unsigned char l1efa(short code, short cnt, short areaflag,
                           struct ua_pick10 *buf)
{
	unsigned char res = 0;
	unsigned char ret;

	PROBE("L1efa");
	if ((unsigned char)cnt == 0) {
		short flag = ((unsigned char)code != 83) ? 1 : 0;
		unsigned char range = jt600(code);
		unsigned char *actor =
		    (unsigned char *)(uintptr_t)g_a5_long(-27932);

		jt539(g_a5_long(-27932), (short)range, (short)0, areaflag,
		      flag, &res, buf);
		*(long *)(void *)
		    (*(unsigned char **)(void *)(actor + 64) + 12) = buf->rec;
	} else if ((unsigned char)areaflag == 0
	           || g_a5_buf(-16906)[(long)(unsigned char)code * 16 + 6]
	              == 8) {
		short s1, s2;
		unsigned char c1;
		char codeb = (char)code;

		res = l1dd6(buf, &s1, &s2, &codeb, &c1);
	} else {
		res = l4dee((short)(unsigned char)code, buf);
	}
	if (res != 0) {
		ret = 1;
		g_a5_byte(-23236) = (unsigned char)buf->x;
		g_a5_byte(-23235) = (unsigned char)buf->y;
	} else {
		ret = 0;
		jt399(buf, (short)10, (short)0);
	}
	return ret;
}

/* JT[538] (CODE 14 + 0x2028) — the IN-COMBAT targeting callback (the
 * -24070 ABI's other implementation; jt511 installs it for combat).
 * Clears the -23512 slot table and stages the picker at the active
 * combatant's cell (jt525/jt531 of -27932), then dispatches on the low
 * nibble of the -16906 hazard row's byte6 (targeting mode):
 *   0  -> self: -23508 = -27932, count 1;
 *   5  -> pick-many under a weight budget: cap = caster level for
 *         code 79, else jt870(2, 4); each unique pick adds rec[137]
 *         (or rec[130] for 79) class weight to the running mask and
 *         stops once count > 1 and the mask exceeds the cap (unsigned);
 *         a duplicate pick costs a cap point on repeat rounds or just
 *         complains on the first;
 *   8-14 -> area: one aimed pick, then jt508 scans the map around the
 *         picked cell (special radii for codes 87/51 vs -28006 byte 60
 *         and 115/47 vs byte 34, else byte6 & 7) and the -19170 match
 *         array is resolved through -25676 into the slots;
 *   15 -> like area but byte6 >> 4 is the radius, and a remembered
 *         pick (actor sub +12) short-circuits to a single target;
 *   default (1-4, 6, 7) -> pick (byte6 & 3) + 1 individual targets,
 *         codes 23/49 may not self-target.
 * Targets land in the -23512 slots (1-based; slot 1 aliases -23508),
 * count in -23510; *out = 0 when no target was chosen. */
static void jt538(short code, short cnt, unsigned char *out)
                                                 __attribute__((unused));
static void jt538(short code, short cnt, unsigned char *out)
{
	const unsigned char *info =
	    g_a5_buf(-16906) + (long)(unsigned char)code * 16;
	struct ua_pick10 buf;

	PROBE("jt538");
	jt65((long)(uintptr_t)&g_a5_long(-23512), (short)4);
	*out = 1;
	g_a5_byte(-23510) = 0;
	g_a5_byte(-25257) = 0;
	g_a5_byte(-23236) = jt525(g_a5_long(-27932));
	g_a5_byte(-23235) = jt531(g_a5_long(-27932));
	switch (info[6] & 15) {
	case 0:		/* self */
		g_a5_long(-23508) = g_a5_long(-27932);
		g_a5_byte(-23510) = 1;
		break;

	case 5: {	/* pick-many under a weight budget */
		unsigned char mask = 0, count = 0, done = 0, cap;

		if ((unsigned char)code == 79)
			cap = (unsigned char)jt17((short)79, (short)0);
		else
			cap = (unsigned char)jt870((short)2, (short)4);
		do {
			if (l1efa(code, cnt, (short)0, &buf) == 0) {
				done = 1;
			} else {
				unsigned char dup = 0, k;
				const unsigned char *rec = (const unsigned
				    char *)(uintptr_t)buf.rec;

				for (k = 1; k <= count; k++)
					if (buf.rec ==
					    g_a5_long(-23512 + (long)k * 4))
						dup = 1;
				if (!dup) {
					count++;
					g_a5_long(-23512 + (long)count * 4) =
					    buf.rec;
					g_a5_byte(-23236) = jt525(buf.rec);
					g_a5_byte(-23235) = jt531(buf.rec);
					g_a5_byte(-23510)++;
					if ((unsigned char)code != 79) {
						switch ((short)rec[137]) {
						case 0: case 1:
							mask += 1; break;
						case 2: mask += 2; break;
						case 3: mask += 4; break;
						default: mask += 8; break;
						}
					} else {
						switch ((short)rec[130]) {
						case 1: mask += 1; break;
						case 2: case 3:
							mask += 2; break;
						case 4: mask += 4; break;
						default: break;
						}
					}
					if (count > 1 && mask > cap)
						done = 1;
				} else if ((unsigned char)cnt != 0) {
					cap--;
				} else {
					jt42(ua_strs_at(0x4680)
					     /* "Already been targeted" */);
				}
				l6090((short)(signed char)jt525(buf.rec),
				      (short)(signed char)jt531(buf.rec));
			}
		} while (!done && cap != 0);
		break;
	}

	case 8: case 9: case 10: case 11:
	case 12: case 13: case 14: {	/* aimed area */
		const unsigned char *st = (const unsigned char *)g_a5_28006;
		unsigned char k;

		if (l1efa(code, cnt, (short)1, &buf) == 0) {
			*out = 0;
			break;
		}
		if ((unsigned char)code == 87 && st[60] != 0)
			jt508((short)(signed char)g_a5_byte(-23236),
			      (short)(signed char)g_a5_byte(-23235),
			      (short)3, (short)255, (short)1);
		else if ((unsigned char)code == 51 && st[60] != 0)
			jt508((short)(signed char)g_a5_byte(-23236),
			      (short)(signed char)g_a5_byte(-23235),
			      (short)2, (short)255, (short)1);
		else if ((unsigned char)code == 115 && st[34] == 0)
			jt508((short)(signed char)g_a5_byte(-23236),
			      (short)(signed char)g_a5_byte(-23235),
			      (short)2, (short)255, (short)1);
		else if ((unsigned char)code == 47 && st[34] == 0)
			jt508((short)(signed char)g_a5_byte(-23236),
			      (short)(signed char)g_a5_byte(-23235),
			      (short)2, (short)255, (short)1);
		else
			jt508((short)(signed char)g_a5_byte(-23236),
			      (short)(signed char)g_a5_byte(-23235),
			      (short)(info[6] & 7), (short)255, (short)1);
		/* resolve the -19170 match array through -25676 */
		for (k = 1; k <= g_a5_18894; k++)
			g_a5_long(-23512 + (long)k * 4) =
			    g_a5_25676[g_a5_19170[(long)k * 4]];
		g_a5_byte(-23510) = g_a5_18894;
		g_a5_byte(-25257) = 1;
		break;
	}

	case 15: {	/* area with remembered-pick short circuit */
		unsigned char *actor =
		    (unsigned char *)(uintptr_t)g_a5_long(-27932);
		long remembered;
		unsigned char k;

		if (l1efa(code, cnt, (short)0, &buf) == 0) {
			*out = 0;
			break;
		}
		remembered = *(long *)(void *)
		    (*(unsigned char **)(void *)(actor + 64) + 12);
		if (remembered != 0) {
			g_a5_long(-23508) = remembered;
			g_a5_byte(-23510) = 1;
			break;
		}
		jt508((short)(signed char)g_a5_byte(-23236),
		      (short)(signed char)g_a5_byte(-23235),
		      (short)(info[6] >> 4), (short)255, (short)1);
		for (k = 1; k <= g_a5_18894; k++)
			g_a5_long(-23512 + (long)k * 4) =
			    g_a5_25676[g_a5_19170[(long)k * 4]];
		g_a5_byte(-23510) = g_a5_18894;
		g_a5_byte(-25257) = 1;
		break;
	}

	default: {	/* 1-4, 6, 7: (byte6 & 3) + 1 individual picks */
		unsigned char remaining = (unsigned char)((info[6] & 3) + 1);
		unsigned char count = 0;

		while (remaining != 0) {
			unsigned char dup, k;

			if (l1efa(code, cnt, (short)0, &buf) == 0) {
				remaining = 0;
				continue;
			}
			dup = 0;
			for (k = 1; k <= count; k++)
				if (buf.rec ==
				    g_a5_long(-23512 + (long)k * 4))
					dup = 1;
			if (((unsigned char)code == 23
			     || (unsigned char)code == 49)
			    && buf.rec == g_a5_long(-27932))
				dup = 1;
			if (!dup) {
				count++;
				g_a5_long(-23512 + (long)count * 4) = buf.rec;
				remaining--;
				g_a5_byte(-23236) = jt525(buf.rec);
				g_a5_byte(-23235) = jt531(buf.rec);
			} else if ((unsigned char)cnt == 0) {
				if (buf.rec == g_a5_long(-27932))
					jt42(ua_strs_at(0x4696)
					     /* "Cannot target yourself" */);
				else
					jt42(ua_strs_at(0x46ae)
					     /* "Already been targeted" */);
			} else {
				remaining--;
			}
			l6090((short)(signed char)jt525(buf.rec),
			      (short)(signed char)jt531(buf.rec));
		}
		g_a5_byte(-23510) = count;
		if (count == 0) {
			*out = 0;
		} else {
			long last = g_a5_long(-23512 + (long)count * 4);

			g_a5_byte(-23236) = jt525(last);
			g_a5_byte(-23235) = jt531(last);
		}
		break;
	}
	}
}

/* CODE 16 + 0x698a — seed a combat_walk's endpoints from (sign-extended)
 * byte coords and run the walker init (jt509). */
static void l698a(short x0, short y0, short x1, short y1,
                  struct combat_walk *w)
{
	PROBE("L698a");
	w->x0 = (short)(signed char)x0;
	w->y0 = (short)(signed char)y0;
	w->x1 = (short)(signed char)x1;
	w->y1 = (short)(signed char)y1;
	jt509(w);
}

/* CODE 16 + 0x69d2 — clamp a combat-map coord pair to 0..49 x 0..24
 * (signed byte compares; negative folds to 0). */
static void l69d2(unsigned char *px, unsigned char *py)
{
	PROBE("L69d2");
	if ((signed char)*px > 49)
		*px = 49;
	else if ((signed char)*px < 0)
		*px = 0;
	if ((signed char)*py > 24)
		*py = 24;
	else if ((signed char)*py < 0)
		*py = 0;
}

/* CODE 16 + 0x6a1e — run a combat_walk ray to its end, inserting each
 * cell's occupant (l62ec) into the NUL-terminated dedup array `arr`:
 * an existing match stops the scan, else the first empty slot takes it. */
static void l6a1e(unsigned char *arr, unsigned char *featp,
                  unsigned char *occp, struct combat_walk *w,
                  unsigned char *donep)
{
	PROBE("L6a1e");
	do {
		*donep = (unsigned char)(jt507(w) == 0);
		if (*donep == 0) {
			short k = 1;
			unsigned char fin = 0;
			l62ec(w->cx, w->cy, occp, featp);
			if (*occp == 0)
				continue;
			while (!fin) {
				if (arr[k - 1] == *occp) {
					fin = 1;
				} else if (arr[k - 1] == 0) {
					arr[k - 1] = *occp;
					fin = 1;
				} else {
					k++;
				}
			}
		}
	} while (*donep == 0);
}

/* JT[596] (CODE 16 + 0x6af8) — the area-effect target-list builder
 * (breath weapons / bolts / cones).  Bresenham-walks a ray from the
 * caster (x0,y0) through the picked cell (tx,ty) recording its
 * direction pattern, extends the ray past the pick out to range*2
 * movement points (orthogonal step = 2, diagonal = 3) by replaying the
 * pattern cyclically, clamps (l69d2) and re-resolves the endpoint
 * against the path-cost walker (jt506), then collects every occupant
 * along the final ray into a 30-byte dedup array.  Modes 2+ add the
 * flanking cone rays (the -5946/-5938 and -5930/-5922 per-octant offset
 * tables, off the last hit's direction; mode 3 takes both flanks).
 * Mode 255 instead takes the jt508 radius-3 -19170 sweep.  The array is
 * finally resolved through the -25676 entity table into the -23512
 * target slots (the caster -27932 excluded), count in -23510.
 * Mac quirks kept: the -22307 scratch byte is a real A5 global, and the
 * inline dedup flag is NOT recleared after a duplicate hit, so the cell
 * after a duplicate is dropped too (the factored flank-ray collector
 * l6a1e does not share the bug). */
static void jt596(short x0, short y0, short tx, short ty, short mode,
                  short range) __attribute__((unused));
static void jt596(short x0, short y0, short tx, short ty, short mode,
                  short range)
{
	struct combat_walk walk;
	unsigned char dircodes[50];
	unsigned char arr[30];
	unsigned char txb = (unsigned char)tx;
	unsigned char tyb = (unsigned char)ty;
	unsigned char budget, last, cost, done, occ, feat;
	unsigned char n = 0, count, slot, lastdir = 0, dup = 0;
	unsigned short cost16;

	PROBE("jt596");
	l698a(x0, y0, (short)txb, (short)tyb, &walk);

	/* phase 1: run the ray once, recording its direction pattern */
	do {
		done = (unsigned char)(jt507(&walk) == 0);
		if (done == 0)
			dircodes[n++] = walk.dircode;
	} while (done == 0);
	last = (unsigned char)(n - 1);
	n = 0;

	/* phase 2: extend past the pick, replaying the pattern */
	budget = (unsigned char)((unsigned char)range * 2);
	cost = walk.steps;
	done = 0;
	while (cost < budget && done == 0) {
		if ((signed char)txb >= 49 || (signed char)txb <= 0
		 || (signed char)tyb >= 24 || (signed char)tyb <= 0) {
			done = 1;
			continue;
		}
		switch ((short)dircodes[n]) {
		case 0: case 2: case 4: case 6:
			cost = (unsigned char)(cost + 2);
			break;
		case 1: case 3: case 5: case 7:
			cost = (unsigned char)(cost + 3);
			break;
		default:
			break;
		}
		txb = (unsigned char)(txb + g_a5_buf(-27862)[dircodes[n]]);
		tyb = (unsigned char)(tyb + g_a5_buf(-27853)[dircodes[n]]);
		if (n == last)
			n = 0;
		else
			n++;
	}

	/* clamp + re-resolve the endpoint against the cost walker */
	l69d2(&txb, &tyb);
	cost16 = budget;
	(void)jt506((short)(signed char)x0, (short)(signed char)y0,
	            &txb, &tyb, &cost16);
	l698a(x0, y0, (short)txb, (short)tyb, &walk);

	/* phase 3: collect occupants along the final ray */
	jt65((long)(uintptr_t)arr, 30);
	count = 1;
	do {
		done = (unsigned char)(jt507(&walk) == 0);
		if (done == 0) {
			l62ec(walk.cx, walk.cy, &occ, &feat);
			if (occ != 0) {
				if (count > 1) {
					/* dup NOT recleared here (Mac bug) */
					for (g_a5_byte(-22307) = 1;
					     (unsigned char)g_a5_byte(-22307)
					       <= (unsigned char)(count - 1);
					     g_a5_byte(-22307)++)
						if (arr[(unsigned char)
						        g_a5_byte(-22307) - 1]
						    == occ)
							dup = 1;
				} else {
					dup = 0;
				}
				if (dup == 0) {
					arr[count - 1] = occ;
					count++;
				}
				lastdir = walk.dircode;
			}
		}
	} while (done == 0);

	/* cone modes: the two flanking rays off the last hit's octant */
	if ((unsigned char)mode > 1 && (unsigned char)mode != 255) {
		unsigned char fx1, fy1, fx2, fy2;
		fx1 = (unsigned char)((short)(signed char)
		        g_a5_buf(-5946)[lastdir] + (short)(signed char)txb);
		fy1 = (unsigned char)((short)(signed char)
		        g_a5_buf(-5938)[lastdir] + (short)(signed char)tyb);
		l69d2(&fx1, &fy1);
		fx2 = (unsigned char)((short)(signed char)
		        g_a5_buf(-5930)[lastdir] + (short)(signed char)txb);
		fy2 = (unsigned char)((short)(signed char)
		        g_a5_buf(-5922)[lastdir] + (short)(signed char)tyb);
		l69d2(&fx2, &fy2);
		l698a(x0, y0, (short)fx2, (short)fy2, &walk);
		l6a1e(arr, &feat, &occ, &walk, &done);
		if ((unsigned char)mode > 2) {
			l698a(x0, y0, (short)fx1, (short)fy1, &walk);
			l6a1e(arr, &feat, &occ, &walk, &done);
		}
	}

	/* mode 255: the radius-3 jt508 sweep instead */
	if ((unsigned char)mode == 255) {
		jt508((short)(signed char)txb, (short)(signed char)tyb,
		      3, 255, 1);
		for (g_a5_byte(-22307) = 1;
		     (unsigned char)g_a5_byte(-22307)
		       <= (unsigned char)g_a5_18894;
		     g_a5_byte(-22307)++)
			arr[(unsigned char)g_a5_byte(-22307) - 1] =
			    g_a5_buf(-19170)
			        [(long)(unsigned char)g_a5_byte(-22307) * 4];
	}

	/* resolve the array into -23512 entity slots, caster excluded */
	count = 1;
	slot = 1;
	g_a5_byte(-23510) = 0;
	if (arr[0] == 0)
		return;
	do {
		long e = *(long *)(void *)(g_a5_buf(-25676)
		                           + (long)arr[count - 1] * 4);
		if (e != g_a5_long(-27932)) {
			g_a5_byte(-23510)++;
			g_a5_long(-23512 + (long)slot * 4) = e;
			slot++;
		}
		count++;
	} while (arr[count - 1] != 0);
}

