/* JT[460] (CODE 3+0xc0a) — append `length` raw bytes from the open
 * refnum onto the current group. A negative length means "read to EOF"
 * (tell, seek to LEOF for the size, seek back). The low bit of the
 * packed long is a +1 odd-size pad. Returns 1 on a complete read. */
static unsigned char jt460(short refnum, long arg) __attribute__((unused));
static unsigned char jt460(short refnum, long arg)
{
	long  length = arg;
	short flagbit0 = (short)(arg & 1);
	long  avail, dest;

	PROBE("jt460");
	if (length < 0) {                          /* read-to-EOF */
		long tellpos = jt412(refnum, 0, 1);    /* tell (from mark) */

		if (tellpos < 0)
			return 0;
		length = jt412(refnum, 0, 2);          /* LEOF -> total size */
		if (length < 0)
			return 0;
		if (jt412(refnum, tellpos, 0) < 0)     /* seek back */
			return 0;
		length -= tellpos;
	}

	/* old end of the current group = slot[count-1] + (slot[count]-slot[count-1]) */
	avail = g_a5_10270[g_a5_9306] - g_a5_10270[g_a5_9306 - 1];
	if (!l0ab8(length + flagbit0))
		return 0;
	dest = g_a5_10270[g_a5_9306 - 1] + avail;

	{
		/* jt401 takes a 16-bit count (the Mac's PBRead.ioReqCount is a long,
		 * but the port's File shim caps at a short), so a library larger than
		 * 32KB must be read in <=32000-byte chunks. The old single
		 * `(short)length` read truncated to the low 16 bits — BIGPIX.CTL's
		 * 165330 became (short)165330 == -31278, so only ~34KB was read, the
		 * group came up short, and the bigpic load crashed the play screen
		 * (#129). Every library over 32KB (the bigpics, the larger wall/frame
		 * sets) hit this; the boot UI .ctls are all under 32KB, which is why it
		 * only surfaced on the bigpic. */
		long  off = 0, remaining = length;

		while (remaining > 0) {
			short chunk = (remaining > 32000L) ? (short)32000
			                                   : (short)remaining;
			short got = jt401(refnum,
			                  (void *)(uintptr_t)(dest + off), chunk);
			if (got != chunk)
				return 0;
			off       += got;
			remaining -= got;
		}
		return 1;
	}
}

