/* =====================================================================
 * FC group-cache correctness audit (probe-only).
 *
 * Exercises the REAL lifted FC cache end-to-end on an isolated scratch
 * pool — register (jt464) / resolve (jt468) / append (jt467) / size
 * (jt459) / MRU promotion / orphan purge (l11ca -> l103c) / drop (jt462)
 * / flush (jt465) — asserting the documented invariants after each step.
 * Runs at boot (conout live) under FRUA_ENGINE_PROBE, after the pool
 * self-test. Uses group tags 5..8 so jt468's UI shortcut (groups 0/1/24
 * -> resident ALWAYS/FRAME) never fires; all reads go through the
 * scratch pool. Saves and restores the entire live FC A5 state around
 * itself, and stands the scratch pool up by hand (no jt463) so the
 * converter registry and the live pool are left untouched. A non-zero
 * "FC AUDIT fail" count in the boot log flags a regression in the cache.
 * ===================================================================== */
#ifdef FRUA_ENGINE_PROBE
static short g_fca_pass, g_fca_fail;
static void fca_check(const char *name, long got, long want)
{
	if (got == want) {
		g_fca_pass++;
	} else {
		g_fca_fail++;
		dbg_log_num(name, got);
		dbg_log_num("   FC AUDIT expected", want);
	}
}
static void fc_cache_audit(void)
{
	static unsigned char sv_recs[48 * 14];
	static long          sv_slots[50];
	short         sv_count = g_a5_9306, sv_9296 = g_a5_9296;
	short         sv_9294 = g_a5_9294, sv_9292 = g_a5_9292;
	long          sv_cap = g_a5_9304, sv_hi = g_a5_9300;
	unsigned char sv_freemap[48], sv_mru[48];
	unsigned char tmp[40];
	char         *scratch;
	short         i;

	for (i = 0; i < 48; i++) { sv_freemap[i] = g_a5_10074[i];
	                           sv_mru[i]     = g_a5_9354[i]; }
	for (i = 0; i < 50; i++)        sv_slots[i] = g_a5_10270[i];
	for (i = 0; i < 48 * 14; i++)   sv_recs[i]  = g_a5_10026[i];
	for (i = 0; i < 40; i++)        tmp[i]      = (unsigned char)i;

	scratch = (char *)NewPtr((Size)4096);
	if (scratch == NULL) { dbg_log("FC AUDIT: no scratch RAM"); return; }
	g_fca_pass = 0; g_fca_fail = 0;

	/* isolated 4096-byte pool, stood up by hand (no jt463) */
	g_a5_9306 = 0;
	jt399(g_a5_10074, 48, -1);
	jt399(g_a5_10026, (short)G_A5_10026_LEN, 0);
	g_a5_10270[0] = (long)(uintptr_t)scratch;
	g_a5_9304     = (long)(uintptr_t)scratch + 4096;
	g_a5_9300 = 4096; g_a5_9296 = 0; g_a5_9294 = 0; g_a5_9292 = 0;

	/* T1 fresh-pool invariants */
	fca_check("FC.t1 count",   g_a5_9306, 0);
	fca_check("FC.t1 cap",     jt459(-2), 4096);
	fca_check("FC.t1 free",    jt459(-1), 4096);

	/* T2 register group 5 (ALPHA -> record 0) */
	fca_check("FC.t2 new=0",   jt464("ALPHA", 5), 0);
	fca_check("FC.t2 count",   g_a5_9306, 1);
	fca_check("FC.t2 g5->r0",  (signed char)g_a5_10074[5], 0);
	fca_check("FC.t2 mru0",    g_a5_9354[0], 0);
	fca_check("FC.t2 resolve", jt468(5), g_a5_10270[0]);
	fca_check("FC.t2 empty",   jt459(5), 0);

	/* T3 append 16 bytes to ALPHA (the in-progress group) */
	fca_check("FC.t3 append",  jt467((long)(uintptr_t)tmp, 16), 1);
	fca_check("FC.t3 size",    jt459(5), 16);
	fca_check("FC.t3 free",    jt459(-1), 4096 - 16);

	/* T4 register group 6 (BETA -> record 1) + append 32 bytes */
	fca_check("FC.t4 new=0",   jt464("BETA", 6), 0);
	fca_check("FC.t4 count",   g_a5_9306, 2);
	fca_check("FC.t4 g6->r1",  (signed char)g_a5_10074[6], 1);
	fca_check("FC.t4 mru0",    g_a5_9354[0], 1);
	fca_check("FC.t4 mru1",    g_a5_9354[1], 0);
	fca_check("FC.t4 resolve", jt468(6), g_a5_10270[0] + 16);
	jt467((long)(uintptr_t)tmp, 32);
	fca_check("FC.t4 size",    jt459(6), 32);

	/* T5 cache hit + MRU promotion: re-register ALPHA under group 7 */
	fca_check("FC.t5 cached=1", jt464("ALPHA", 7), 1);
	fca_check("FC.t5 count",    g_a5_9306, 2);            /* no new record */
	fca_check("FC.t5 g7->r0",   (signed char)g_a5_10074[7], 0);
	fca_check("FC.t5 promote",  g_a5_9354[0], 0);         /* ALPHA to front */
	fca_check("FC.t5 mru1",     g_a5_9354[1], 1);
	fca_check("FC.t5 alias",    jt468(7), jt468(5));

	/* T6 size of an unbound group */
	fca_check("FC.t6 unbound",  jt459(9), 0);

	/* T7 orphan BETA (record 1; only group 6 referenced it) and purge it */
	jt461(6);                                             /* unbind group 6 */
	fca_check("FC.t7 orphaned", (l3e0c(g_a5_10074, 48, 1) >= 48), 1);
	fca_check("FC.t7 free-pre", jt459(-1), 4096 - 16);    /* only ALPHA counts */
	fca_check("FC.t7 purge",    l11ca(0), 1);             /* reclaim the orphan */
	fca_check("FC.t7 count",    g_a5_9306, 1);
	fca_check("FC.t7 keepalpha",(signed char)g_a5_10074[5], 0);
	fca_check("FC.t7 size",     jt459(5), 16);            /* compaction intact */
	fca_check("FC.t7 free-post",jt459(-1), 4096 - 16);

	/* T8 drop the in-progress group (jt462) */
	fca_check("FC.t8 new=0",    jt464("GAMMA", 8), 0);
	fca_check("FC.t8 count2",   g_a5_9306, 2);
	jt462();
	fca_check("FC.t8 dropped",  g_a5_9306, 1);
	fca_check("FC.t8 g8-free",  (signed char)g_a5_10074[8], -1);

	/* T9 full flush (jt465 NULL) */
	jt465(NULL);
	fca_check("FC.t9 count0",   g_a5_9306, 0);
	fca_check("FC.t9 g5-free",  (signed char)g_a5_10074[5], -1);

	dbg_log_num("FC AUDIT pass = ", g_fca_pass);
	dbg_log_num("FC AUDIT fail = ", g_fca_fail);

	/* restore the live FC A5 state */
	g_a5_9306 = sv_count; g_a5_9304 = sv_cap; g_a5_9300 = sv_hi;
	g_a5_9296 = sv_9296; g_a5_9294 = sv_9294; g_a5_9292 = sv_9292;
	for (i = 0; i < 48; i++) { g_a5_10074[i] = sv_freemap[i];
	                           g_a5_9354[i]  = sv_mru[i]; }
	for (i = 0; i < 50; i++)      g_a5_10270[i] = sv_slots[i];
	for (i = 0; i < 48 * 14; i++) g_a5_10026[i] = sv_recs[i];
	DisposePtr((Ptr)scratch);
}
#else
static void fc_cache_audit(void) { }
#endif

/* JT[403] (CODE 3+0x38ea) — query a file's length without moving its
 * mark (Mac PBGetEOF via JT[1047]). The port routes through jt412:
 * remember the mark, seek to LEOF for the size, restore the mark. */
static long jt403(short refnum) __attribute__((unused));
static long jt403(short refnum)
{
	long cur  = jt412(refnum, 0, 1);     /* tell */
	long size = jt412(refnum, 0, 2);     /* LEOF -> size */

	if (cur < 0 || size < 0)
		return -1;
	jt412(refnum, cur, 0);               /* restore the mark */
	return size;
}

/* JT[972] (CODE 5+0x3682) — the library-load callback jt1014 hands to
 * jt987: read the whole open file into the current group (-3622) via
 * jt1016 (jt403 sizes it). Matches the glib_load_cb shape. */
static unsigned char jt972(short refnum, void *spec) __attribute__((unused));
static unsigned char jt972(short refnum, void *spec)
{
	PROBE("jt972");
	(void)spec;
	return (unsigned char)jt1016(refnum, jt403(refnum), g_a5_3622);
}

/* JT[1014] (CODE 5+0x36a4) — the plain-name library loader. Build the
 * filename (default '.GLB' extension), register/create the group
 * (jt464); if it isn't already cached, stamp the current-load group
 * (-3622) and open it through jt987 with jt972 as the read callback.
 * Finally validate the loaded 'GLIB' header in place. */
static void jt1014(short kind, const char *name, short group)
{
	char          buf[216];
	unsigned char hdr[16];

	PROBE("jt1014");
	jt384(buf, name);
	jt419(buf, "GLB", 0);                       /* default extension */
	if (jt464(buf, group) == 0) {               /* not cached -> load */
		g_a5_3622 = group;
		jt987(kind, buf, 0, (void *)jt972);
	}
	jt406(hdr, (const void *)(uintptr_t)jt468(group), 16);
	if (*(const long *)hdr != 0x474C4942L)
		l036a("LBLoad: Bad Lib: '%s'", buf);
}

/* JT[997] (CODE 5+0x27be) — plain-name (no numeric suffix) loader: build
 * "<name>.CTL" / ".TLB" and hand off to the jt1014 cache loader. With
 * jt464/jt1014 now real, this stands the library up through the faithful
 * FAR-pool path. */
static unsigned char jt997(short mode, const char *name, short group)
    __attribute__((unused));
static unsigned char jt997(short mode, const char *name, short group)
{
	char buf[200];

	PROBE("jt997");
	jt384(buf, name);
	jt419(buf, (jt1200() == 3) ? "TLB" : "CTL", 1);
	jt1014(mode, buf, group);
	return 0;
}

/* JT[110] / L33ac (CODE 6+0x33ac) — the library binder. Claims a -18468
 * binder slot, builds the library's filename, stamps the binder context
 * (-18402/-18406/-18408/-18404/-18398) and dispatches the load: plain
 * names go to jt997, numeric-suffixed names to jt987 with jt104 as the
 * per-file callback. Structural skeleton (level 2): the slot/context
 * spine and dispatch are faithful; the dual filename-format arms are
 * condensed and the jt464/jt997/jt1014 cache leaves are stubs. */
static void l33ac(const char *name, short kindB, short modeB, short subB,
                  void **slotpp) __attribute__((unused));
static void l33ac(const char *name, short kindB, short modeB, short subB,
                  void **slotpp)
{
	char   namebuf[210];      /* fp@(-220): working/numbered filename     */
	char   fullname[210];     /* fp@(-206): the name handed to jt987      */
	char   path[420];         /* fp@(-420): prefix + name for the open    */
	short  i, len, digit, refnum;
	short *slot;

	PROBE("L33ac");

	/* release any binding already parked in *slotpp */
	if (*slotpp != NULL)
		l31dc(slotpp);

	/* claim the first free -18468 slot (10 x 6 bytes; word[0] < 0 == free) */
	for (i = 0; i < 10; i++)
		if (*(short *)&g_a5_18468[i * 6] < 0)
			break;
	slot = (short *)(void *)&g_a5_18468[i * 6];
	*slotpp = slot;
	slot[0] = (short)(i + 2);          /* group id */
	slot[1] = (short)kindB;            /* kind at +2 */

	len   = jt423(name);
	digit = (short)(unsigned char)name[len - 1];

	if (!jt389(digit)) {                       /* plain name -> jt997 */
		jt997(g_a5_18396, name, (short)(i + 2));
		return;
	}

	/* numbered name: strip the digit, build "<base>.ctl"/".tlb" for jt987
	 * and the concrete "<base><kind><nnn>.ctl" for the existence/open. */
	slot[1] = 0;
	digit  -= '0';
	jt384(namebuf, name);
	namebuf[len - 1] = 0;

	/* GEMDOS 8.3 fallback: the per-design override file is
	 * "<base><digit><kind:03d>.ctl" — its base is strlen(base)+4 chars, so for
	 * any base > 4 it can NEVER exist on a GEMDOS volume (the name clips). That
	 * is the faithful "no design override present" case, so load the base
	 * library directly through the plain-name path (jt997 -> "<base>.ctl") and
	 * skip the override concrete-open + jt104 machinery entirely. (HEIRS ships
	 * no overrides; without this the bigpic/wall override names clip and the
	 * load stalls.) */
	if (jt423(namebuf) > 4) {
		slot[1] = (short)kindB;
		jt997(g_a5_18396, namebuf, (short)(i + 2));
		return;
	}
	/* concrete name from the BASE (an earlier cut formatted it from
	 * `fullname`, yielding "bigpix.ctl0008.ctl" — the GEMDOS 8.3 clip
	 * then missed the file); `path` is free until the open below. */
	jt394(path, (jt1200() == 3) ? "%s%d%03d.tlb" : "%s%d%03d.ctl",
	      namebuf, digit, (short)kindB);
	jt394(fullname, (jt1200() == 3) ? "%s.tlb" : "%s.ctl", namebuf);
	jt384(namebuf, path);

	if (jt464(namebuf, (short)(i + 2))) {      /* already present -> bail */
		g_a5_18397 = 0;
		return;
	}
	g_a5_18397 = 1;

	/* read the whole library into the pool up front (inline open path) */
	path[0] = 0;
	jt431(path, g_a5_buf(-31336));             /* directory prefix */
	jt431(path, namebuf);
	refnum = jt398(path, 0);
	if (refnum >= 0) {
		jt460(refnum, -1);                 /* read-to-EOF into the pool */
		jt411(refnum);
	}

	/* stamp the binder context jt104 will read (consumed synchronously
	 * inside jt987's callback, while this frame is still live) */
	g_a5_18402 = (long)(uintptr_t)namebuf;
	g_a5_18408 = (short)kindB;
	g_a5_18406 = (short)(i + 2);
	g_a5_18404 = digit;
	g_a5_18398 = (modeB == 3) ? 1 : 0;
	if (g_a5_18398 != 0 && subB == 15)
		g_a5_18398 = 2;

	jt987(g_a5_18396, fullname, 0, (void *)jt104);
}

